      have hck2 : (ck : ℝ) = Nk - (excSet BS a k).card := by
        exact eq_sub_of_add_eq <| mod_cast Finset.card_sdiff_add_card_eq_card <| Finset.filter_subset _ _;
      linarith
    have hck3 : (ck1 : ℝ) - 1 ≥ Nk1 - e0 - 1 := by
      linarith
    have hck4 : ((ck1 : ℝ) - 1) * (ck : ℝ) ^ 3 / (2 ^ 13 * (2 ^ k : ℝ) ^ 2) ≤ Xen BS a k := by
      apply mismatch_penalty_with_exceptions BS (toPlain BS a) k (coldLabel BS a k) (coldLabel BS a (k + 1)) (by
      unfold boundarySet at hk6; aesop;) (excSet BS a k) (excSet BS a (k + 1)) (excSet_subset BS a k) (excSet_subset BS a (k + 1)) (by
      exact hCBF BS a k hk1 ( by linarith ) hk3 ( by unfold boundarySet at hk6; aesop ) |>.2.2) (by
      have := hCBF BS a ( k + 1 ) ( by linarith ) ( by linarith ) ( by linarith [ pow_le_pow_right₀ ( by norm_num : ( 1 : ℝ ) ≤ 2 ) ( by linarith : k + 1 ≥ k ) ] ) ( by
        unfold boundarySet at hk6; aesop; ) ; aesop;) hNk hm hm'
    exact (by
    refine le_trans ?_ hck4;
    unfold Pifloor; gcongr;
    · exact pow_nonneg ( sub_nonneg_of_le <| by linarith [ show ( Nk : ℝ ) ≥ 2 * e0 + 13 by
                                                            have := BS.hdensity k hk1 ( by linarith ) ; norm_num at *;
                                                            have := hden ( 2 ^ k ) ( by exact_mod_cast hk4 ) ; norm_num at *;
                                                            rw [ div_le_iff₀ ] at * <;> nlinarith [ show ( k : ℝ ) * Real.log 2 > 0 by exact mul_pos ( Nat.cast_pos.mpr ( Nat.pos_of_ne_zero ( by rintro rfl; linarith ) ) ) ( Real.log_pos one_lt_two ) ] ] ) _;
    · have := BS.hdensity ( k + 1 ) ( by linarith [ show k + 1 ≥ BS.k0 from by linarith ] ) ( by linarith ) ; norm_num at *;
      refine' Nat.pos_of_ne_zero _;
      intro h; norm_num [ h ] at *;
      have := hden ( 2 ^ ( k + 1 ) ) ( by exact_mod_cast hk4.trans ( pow_le_pow_right₀ ( by norm_num ) ( Nat.le_succ _ ) ) ) ; norm_num at *;
      rw [ div_le_iff₀ ] at * <;> nlinarith [ show 0 < ( k + 1 : ℝ ) * Real.log 2 by positivity, show ( 2 : ℝ ) ^ ( k + 1 ) > 0 by positivity ];
    · have := BS.hdensity k hk1 ( by linarith ) ; norm_num [ Real.log_pow ] at this;
      have := hden ( 2 ^ k ) ( mod_cast hk4 ) ; norm_num at *;
      rw [ div_le_iff₀ ] at * <;> nlinarith [ show ( k : ℝ ) ≥ 1 by norm_cast; linarith [ show k > 0 from Nat.pos_of_ne_zero ( by rintro rfl; linarith [ Nat.le_ceil X0cbf ] ) ], Real.log_pos one_lt_two, mul_pos ( show ( k : ℝ ) > 0 by norm_cast; linarith [ show k > 0 from Nat.pos_of_ne_zero ( by rintro rfl; linarith [ Nat.le_ceil X0cbf ] ) ] ) ( Real.log_pos one_lt_two ) ])

lemma gaussian_int_sum_le (A : ℝ) (hA0 : 0 < A) (hA1 : A ≤ 1) :
    ∑' m : ℤ, Real.exp (-A * (m : ℝ) ^ 2) ≤ 1 + 6 / Real.sqrt A := by
  -- Let s := Real.sqrt A, so 0 < s ≤ 1 and s^2 = A (since 0 < A ≤ 1).
  set s := Real.sqrt A with hs_def
  have hs_pos : 0 < s := by
    exact Real.sqrt_pos.mpr hA0
  have hs_le_one : s ≤ 1 := by
    exact Real.sqrt_le_iff.mpr ⟨ by positivity, by linarith ⟩
  have hs_sq_eq_A : s^2 = A := by
    exact Real.sq_sqrt hA0.le;
  -- The sum over ℤ is 1 + 2 * ∑'_{n≥1} exp(-A*n^2).
  have h_sum_decomp : ∑' m : ℤ, Real.exp (-A * m ^ 2) = 1 + 2 * ∑' n : ℕ, Real.exp (-A * (n + 1) ^ 2) := by
    have h_sum_decomp : ∑' m : ℤ, Real.exp (-A * m ^ 2) = ∑' m : ℕ, Real.exp (-A * m ^ 2) + ∑' m : ℕ, Real.exp (-A * (-(m + 1) : ℤ) ^ 2) := by
      rw [ ← Equiv.tsum_eq ( Equiv.intEquivNat.symm ) ];
      rw [ ← tsum_even_add_odd ] <;> norm_num [ Equiv.intEquivNat ];
      · norm_num [ Equiv.intEquivNatSumNat ];
      · have h_summable : Summable (fun n : ℕ => Real.exp (-A * n ^ 2)) := by
          have := summable_geometric_of_lt_one ( by positivity ) ( Real.exp_lt_one_iff.mpr ( neg_lt_zero.mpr hA0 ) );
          exact this.of_nonneg_of_le ( fun n => by positivity ) fun n => by rw [ ← Real.exp_nat_mul ] ; ring_nf; gcongr ; norm_cast ; nlinarith;
        simpa using h_summable;
      · norm_num [ Equiv.intEquivNatSumNat ];
        have := summable_geometric_of_lt_one ( by positivity ) ( Real.exp_lt_one_iff.mpr ( show -A < 0 by linarith ) );
        exact this.of_nonneg_of_le ( fun n => by positivity ) fun n => by rw [ ← Real.exp_nat_mul ] ; ring_nf; gcongr ; nlinarith;
    rw [ h_sum_decomp, Summable.tsum_eq_zero_add ] <;> norm_num ; ring;
    have := summable_geometric_of_lt_one ( by positivity ) ( Real.exp_lt_one_iff.mpr ( neg_lt_zero.mpr hA0 ) );
    exact this.of_nonneg_of_le ( fun n => by positivity ) fun n => by rw [ ← Real.exp_nat_mul ] ; ring_nf; gcongr ; norm_cast ; nlinarith;
  -- For 1 ≤ n ≤ N: exp(-A n^2) ≤ 1; there are ≤ N ≤ 1/s such terms, contributing ≤ 1/s.
  have h_tail_bound : ∑' n : ℕ, Real.exp (-A * (n + 1) ^ 2) ≤ ∑ n ∈ Finset.range (Nat.floor (1 / s)), Real.exp (-A * (n + 1) ^ 2) + ∑' n : ℕ, Real.exp (-s * (n + Nat.floor (1 / s) + 1)) := by
    rw [ ← Summable.sum_add_tsum_nat_add ];
    refine' add_le_add le_rfl ( Summable.tsum_le_tsum _ _ _ );
    · intro i; rw [ ← hs_sq_eq_A ] ; ring_nf; norm_num;
      nlinarith only [ show ( 0 : ℝ ) ≤ s * i by positivity, show ( 0 : ℝ ) ≤ s * ⌊s⁻¹⌋₊ by positivity, show ( 0 : ℝ ) ≤ s ^ 2 * i by positivity, show ( 0 : ℝ ) ≤ s ^ 2 * ⌊s⁻¹⌋₊ by positivity, Nat.lt_floor_add_one ( s⁻¹ ), mul_inv_cancel₀ ( ne_of_gt hs_pos ), hs_pos, hs_le_one ];
    · have h_summable : Summable (fun n : ℕ => Real.exp (-A * n ^ 2)) := by
        have := Real.summable_exp_nat_mul_of_ge ( show -A < 0 by linarith ) ( show ∀ n : ℕ, ( n : ℝ ) ≤ n ^ 2 by intros n; norm_cast; nlinarith );
        convert this using 1;
      exact_mod_cast h_summable.comp_injective ( add_left_injective ( ⌊1 / s⌋₊ + 1 ) );
    · have h_geo_series : Summable (fun n : ℕ => (Real.exp (-s)) ^ (n + Nat.floor (1 / s) + 1)) := by
        exact Summable.comp_injective ( summable_geometric_of_lt_one ( by positivity ) ( by rw [ Real.exp_lt_one_iff ] ; linarith ) ) fun a b h => by simpa using h;
      convert h_geo_series using 2 ; norm_num [ ← Real.exp_nat_mul ] ; ring;
    · have := summable_geometric_of_lt_one ( by positivity ) ( Real.exp_lt_one_iff.mpr ( show -A < 0 by linarith ) );
      exact Summable.of_nonneg_of_le ( fun n => by positivity ) ( fun n => by rw [ ← Real.exp_nat_mul ] ; ring_nf; gcongr ; norm_cast ; nlinarith ) this;
  -- The tail ∑_{n≥1} exp(-s*n) = exp(-s)/(1-exp(-s)) = 1/(exp s - 1) ≤ 1/s (because exp s - 1 ≥ s for all s).
  have h_tail_sum : ∑' n : ℕ, Real.exp (-s * (n + Nat.floor (1 / s) + 1)) ≤ 1 / s := by
    have h_tail_sum : ∑' n : ℕ, Real.exp (-s * (n + Nat.floor (1 / s) + 1)) = Real.exp (-s * (Nat.floor (1 / s) + 1)) / (1 - Real.exp (-s)) := by
      convert HasSum.tsum_eq ( HasSum.mul_left _ <| hasSum_geometric_of_lt_one ( by positivity ) <| show Real.exp ( -s ) < 1 from by rw [ Real.exp_lt_one_iff ] ; linarith ) using 1 ; norm_num [ ← Real.exp_nat_mul ] ; ring;
      exact tsum_congr fun n => by rw [ ← Real.exp_add ] ; ring;
    rw [ h_tail_sum, div_le_div_iff₀ ] <;> norm_num [ Real.exp_neg ];
    · field_simp;
      rw [ mul_comm ];
      gcongr;
      · exact le_mul_of_one_le_right hs_pos.le ( by linarith );
      · linarith [ Real.add_one_le_exp s ];
    · exact inv_lt_one_of_one_lt₀ <| by norm_num; positivity;
    · positivity;
  -- For 1 ≤ n ≤ N: exp(-A n^2) ≤ 1; there are ≤ N ≤ 1/s such terms, contributing ≤ 1/s.
  have h_tail_bound : ∑ n ∈ Finset.range (Nat.floor (1 / s)), Real.exp (-A * (n + 1) ^ 2) ≤ Nat.floor (1 / s) := by
    exact le_trans ( Finset.sum_le_sum fun _ _ => Real.exp_le_one_iff.mpr <| by nlinarith ) <| by norm_num;
  ring_nf at *;
  norm_num [ sub_eq_add_neg, add_comm, add_left_comm, add_assoc ] at * ; nlinarith [ Nat.floor_le ( inv_nonneg.mpr hs_pos.le ), mul_inv_cancel₀ hs_pos.ne' ]

/-! ## G7. Prop 8.1 — global control partition (note 34 G7) -/

/-- The "main arc" set `𝔐_C` (note 34 G6): global assignments that are globally
    diagonal with a small common label `|m| ≤ C/sigmaCtrl`. -/

lemma pow_beats_poly_log (C D : ℝ) (hD : 0 < D) :
    ∃ N : ℕ, ∀ s : ℕ, N ≤ s →
      C + (3 * s / 2) * Real.log 2 + Real.log (Real.log (2 ^ s))
        ≤ D * 2 ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3 := by
  -- We can divide both sides of the equation by $2^{s-1}$, which is positive.
  suffices h_div' : Filter.Tendsto (fun s : ℕ => (C + 3 * s / 2 * Real.log 2 + Real.log (Real.log (2 ^ s))) / (2 ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3)) Filter.atTop (nhds 0) by
    obtain ⟨ N, hN ⟩ := Metric.tendsto_atTop.mp h_div' D hD;
    refine' ⟨ N + 2, fun s hs => _ ⟩ ; specialize hN s ( by linarith ) ; simp_all +decide [ mul_div_assoc ];
    rw [ abs_of_nonneg ( Real.log_nonneg <| by nlinarith [ show ( s : ℝ ) ≥ 2 by norm_cast; linarith, Real.log_two_gt_d9, mul_div_cancel₀ ( 3 : ℝ ) two_ne_zero ] ) ] at hN ; rw [ div_lt_iff₀ <| by exact div_pos ( pow_pos zero_lt_two _ ) <| pow_pos ( mul_pos ( Nat.cast_pos.mpr <| Nat.sub_pos_of_lt <| by linarith ) <| Real.log_pos one_lt_two ) _ ] at hN ; linarith [ abs_le.mp ( show |C + 3 * ( s / 2 : ℝ ) * Real.log 2 + Real.log ( s * Real.log 2 )| ≤ _ from le_of_eq rfl ) ] ;
  -- We'll use the fact that $2^{s-1}$ grows much faster than $(\log (2^{s-1}))^3$.
  have h_exp_growth : Filter.Tendsto (fun s : ℕ => (s : ℝ) / (2 ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3)) Filter.atTop (nhds 0) := by
    -- We can simplify the expression inside the limit.
    suffices h_simp : Filter.Tendsto (fun s : ℕ => (s : ℝ) * (Real.log 2 * (s - 1)) ^ 3 / (2 ^ (s - 1))) Filter.atTop (nhds 0) by
      convert h_simp using 2 ; norm_num [ Real.log_pow ] ; ring;
      cases ‹_› <;> norm_num ; ring;
    -- We can factor out $s^4$ from the numerator and denominator.
    suffices h_factor : Filter.Tendsto (fun s : ℕ => (s ^ 4 : ℝ) / (2 ^ (s - 1))) Filter.atTop (nhds 0) by
      refine' squeeze_zero_norm' _ h_factor ; norm_num;
      refine' ⟨ 2, fun n hn => _ ⟩ ; gcongr;
      rw [ abs_of_nonneg ( Real.log_nonneg one_le_two ), abs_of_nonneg ( sub_nonneg_of_le ( by norm_cast; linarith ) ) ];
      exact le_trans ( mul_le_mul_of_nonneg_left ( pow_le_pow_left₀ ( mul_nonneg ( Real.log_nonneg one_le_two ) ( sub_nonneg.mpr ( Nat.one_le_cast.mpr ( by linarith ) ) ) ) ( mul_le_of_le_one_left ( sub_nonneg.mpr ( Nat.one_le_cast.mpr ( by linarith ) ) ) ( Real.log_two_lt_d9.le.trans ( by norm_num ) ) ) _ ) ( Nat.cast_nonneg _ ) ) ( by nlinarith [ show ( n : ℝ ) ≥ 2 by norm_cast, pow_two ( n - 1 : ℝ ) ] );
    rw [ ← Filter.tendsto_add_atTop_iff_nat 1 ] ; norm_num;
    refine' squeeze_zero_norm' _ tendsto_inv_atTop_nhds_zero_nat ; norm_num;
    refine' ⟨ 200, fun n hn => _ ⟩ ; rw [ inv_eq_one_div, div_le_div_iff₀ ] <;> norm_cast <;> induction hn <;> norm_num [ Nat.pow_succ ] at *;
    nlinarith [ Nat.zero_le ( 2 ^ ‹_› ), pow_nonneg ( Nat.zero_le ‹_› ) 2, pow_nonneg ( Nat.zero_le ‹_› ) 3, pow_nonneg ( Nat.zero_le ‹_› ) 4 ];
  -- We'll use the fact that $Real.log (Real.log (2 ^ s))$ grows much slower than $s$.
  have h_log_log_growth : Filter.Tendsto (fun s : ℕ => Real.log (Real.log (2 ^ s)) / (2 ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3)) Filter.atTop (nhds 0) := by
    refine' squeeze_zero_norm' _ h_exp_growth;
    norm_num [ Real.log_pow ];
    refine' ⟨ 2, fun n hn => _ ⟩ ; rw [ abs_of_nonneg ( Real.log_nonneg <| by nlinarith [ show ( n : ℝ ) ≥ 2 by norm_cast, Real.log_two_gt_d9, Real.log_le_sub_one_of_pos zero_lt_two ] ) ] ; rw [ abs_of_nonneg ( Real.log_nonneg one_le_two ) ] ; gcongr;
    exact le_trans ( Real.log_le_sub_one_of_pos ( by positivity ) ) ( by nlinarith [ Real.log_le_sub_one_of_pos zero_lt_two, show ( n : ℝ ) ≥ 2 by norm_cast ] );
  convert Filter.Tendsto.add ( Filter.Tendsto.add ( tendsto_const_nhds.mul ( show Filter.Tendsto ( fun s : ℕ => ( 1 : ℝ ) / ( 2 ^ ( s - 1 ) / Real.log ( 2 ^ ( s - 1 ) ) ^ 3 ) ) Filter.atTop ( nhds 0 ) from ?_ ) ) ( h_exp_growth.const_mul ( 3 * Real.log 2 / 2 ) ) ) h_log_log_growth using 2 <;> ring;
  -- We'll use the fact that $(s-1)^3 * (1/2)^{s-1}$ tends to $0$ as $s$ tends to infinity.
  have h_lim : Filter.Tendsto (fun s : ℕ => (s : ℝ) ^ 3 * (1 / 2) ^ s) Filter.atTop (nhds 0) := by
    refine' squeeze_zero_norm' _ tendsto_inv_atTop_nhds_zero_nat;
    norm_num;
    refine' ⟨ 20, fun n hn => _ ⟩ ; rw [ inv_eq_one_div, div_pow, mul_div, div_le_div_iff₀ ] <;> norm_cast <;> induction hn <;> norm_num [ Nat.pow_succ ] at *;
    nlinarith [ Nat.pow_le_pow_left ‹20 ≤ _› 3 ];
  convert h_lim.comp ( Filter.tendsto_sub_atTop_nat 1 ) |> Filter.Tendsto.mul_const ( Real.log 2 ^ 3 ) using 2 <;> norm_num ; ring

/-
**N1 hot charge.**  For a segment start `s` past a uniform threshold, the
    label-window size `2·labelBound c2 s + 1` is dominated by the Peierls energy
    of the predecessor hot block `s-1`.
-/

lemma labelBound_charge_hot (c2 eps : ℝ) (heps : 0 < eps) (hc2 : 0 < c2) :
    ∃ k0min : ℕ, ∀ s : ℕ, k0min ≤ s →
      (2 * (labelBound c2 s : ℝ) + 1) ≤ Real.exp (eps * Rw c2 (s - 1)) := by
  -- By `Int.ceil_le`/`Int.le_ceil`, `(labelBound c2 s : ℝ) ≤ (20/3)*√(c2*2^s)*(16*2^s*log(2^s)) + 1`.
  -- Hence `2*(labelBound c2 s)+1 ≤ (640/3)*√(c2*2^s)*(2^s*log(2^s)) + 3`.
  have h_labelBound_le : ∀ s : ℕ, s ≥ 4 → 2 * (labelBound c2 s : ℝ) + 1 ≤ (640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s)) + 3 := by
    intro s hs; rw [ labelBound ] ; norm_num ; ring_nf ;
    linarith [ Int.ceil_lt_add_one ( Real.sqrt c2 * Real.sqrt ( 2 ^ s ) * s * Real.log 2 * 2 ^ s * ( 320 / 3 ) ) ];
  -- Choose `k0min` large enough so that for all `s ≥ k0min`, `P + 3 ≤ Real.exp (Real.log P + 1)`.
  obtain ⟨k0min, hk0min⟩ : ∃ k0min : ℕ, ∀ s : ℕ, k0min ≤ s → (640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s)) + 3 ≤ Real.exp (Real.log ((640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s))) + 1) := by
    have h_exp_log : ∃ k0min : ℕ, ∀ s : ℕ, k0min ≤ s → (640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s)) ≥ 3 := by
      have h_exp_log : Filter.Tendsto (fun s : ℕ => (640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s))) Filter.atTop Filter.atTop := by
        refine' Filter.tendsto_atTop_mono _ _;
        use fun n => 640 / 3 * Real.sqrt c2 * 2 ^ n * Real.log 2 * n;
        · norm_num [ Real.sqrt_mul, hc2.le ] ; ring_nf ; norm_num;
          exact fun n => le_mul_of_one_le_right ( by positivity ) ( Real.le_sqrt_of_sq_le ( mod_cast Nat.one_le_pow _ _ ( by decide ) ) );
        · exact Filter.Tendsto.atTop_mul_atTop₀ ( Filter.Tendsto.atTop_mul_const ( by positivity ) ( Filter.Tendsto.const_mul_atTop ( by positivity ) ( tendsto_pow_atTop_atTop_of_one_lt one_lt_two ) ) ) tendsto_natCast_atTop_atTop;
      exact Filter.eventually_atTop.mp ( h_exp_log.eventually_ge_atTop 3 );
    obtain ⟨ k0min, hk0min ⟩ := h_exp_log; use k0min; intros s hs; rw [ Real.exp_add, Real.exp_log ( by linarith [ hk0min s hs ] ) ] ; nlinarith [ hk0min s hs, Real.add_one_le_exp 1 ] ;
  obtain ⟨N, hN⟩ : ∃ N : ℕ, ∀ s : ℕ, N ≤ s → Real.log ((640 / 3) * Real.sqrt (c2 * (2 : ℝ) ^ s) * (2 ^ s * Real.log (2 ^ s))) + 1 ≤ eps * c2 * 2 ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3 := by
    have := GlobalControl.pow_beats_poly_log ( Real.log ( 640 / 3 * Real.sqrt c2 ) + 2 ) ( eps * c2 ) ( by positivity );
    obtain ⟨ N, hN ⟩ := this; use N + 4; intros s hs; specialize hN s ( by linarith ) ; simp_all +decide [ Real.log_mul, Real.log_sqrt, hc2.le, ne_of_gt hc2 ] ;
    rw [ Real.log_mul, Real.log_mul, Real.log_mul, Real.log_mul, Real.log_sqrt, Real.log_sqrt ] <;> first | positivity | norm_num ; ring_nf at * ; norm_num at *;
    · grind +splitImp;
    · linarith;
    · linarith;
  use Max.max k0min ( Max.max N 4 ) ; intros s hs ; specialize h_labelBound_le s ( by linarith [ le_max_left k0min ( Max.max N 4 ), le_max_right k0min ( Max.max N 4 ), le_max_left N 4, le_max_right N 4 ] ) ; specialize hk0min s ( by linarith [ le_max_left k0min ( Max.max N 4 ), le_max_right k0min ( Max.max N 4 ), le_max_left N 4, le_max_right N 4 ] ) ; specialize hN s ( by linarith [ le_max_left k0min ( Max.max N 4 ), le_max_right k0min ( Max.max N 4 ), le_max_left N 4, le_max_right N 4 ] ) ; simp_all +decide [ Rw ] ;
  exact h_labelBound_le.trans ( hk0min.trans ( Real.exp_le_exp.mpr ( by simpa only [ mul_assoc, mul_div_assoc ] using hN ) ) )

/-! ### segStarts / labelFin structural helpers -/

/-
Every segment start lies in the block range `[k0, K]`.
-/

lemma segStarts_pred_mem (BS : BlockSystem) (H B : Finset ℕ) {s : ℕ}
    (hs : s ∈ segStarts BS H B) (hne : s ≠ BS.k0) : (s - 1) ∈ H ∨ (s - 1) ∈ B := by
  unfold segStarts at hs; aesop;

/-
The label window is always nonempty (`labelBound`/`L0` are nonnegative).
-/

lemma label_product_le (BS : BlockSystem) (c2 e0 eps R : ℝ) (H B : Finset ℕ)
    (heps : 0 ≤ eps)
    (hRwnn : ∀ j ∈ H, 0 ≤ Rw c2 j)
    (hPinn : ∀ j ∈ B, 0 ≤ Pifloor BS e0 j)
    (hcharge : ∀ s ∈ segStarts BS H B, s ≠ BS.k0 →
        ((labelFin BS c2 R s).card : ℝ) ≤
          (if s - 1 ∈ H then Real.exp (eps * Rw c2 (s - 1))
           else Real.exp (eps * Pifloor BS e0 (s - 1)))) :
    (∏ s ∈ segStarts BS H B, ((labelFin BS c2 R s).card : ℝ))
      ≤ ((labelFin BS c2 R BS.k0).card : ℝ)
          * (∏ j ∈ H, Real.exp (eps * Rw c2 j))
          * (∏ j ∈ B, Real.exp (eps * Pifloor BS e0 j)) := by
  have h_erase : (∏ s ∈ (segStarts BS H B).erase BS.k0, (labelFin BS c2 R s).card : ℝ) ≤ (∏ j ∈ H, Real.exp (eps * Rw c2 j)) * (∏ j ∈ B, Real.exp (eps * Pifloor BS e0 j)) := by
    refine' le_trans ( Finset.prod_le_prod ( fun _ _ => Nat.cast_nonneg _ ) fun s hs => hcharge s _ _ ) _;
    · exact Finset.mem_of_mem_erase hs;
    · exact Finset.ne_of_mem_erase hs;
    · have h_split : (∏ s ∈ (segStarts BS H B).erase BS.k0, (if s - 1 ∈ H then Real.exp (eps * Rw c2 (s - 1)) else Real.exp (eps * Pifloor BS e0 (s - 1)))) = (∏ j ∈ (H ∪ B) ∩ Finset.image (fun s => s - 1) ((segStarts BS H B).erase BS.k0), if j ∈ H then Real.exp (eps * Rw c2 j) else Real.exp (eps * Pifloor BS e0 j)) := by
        refine' Finset.prod_bij ( fun s hs => s - 1 ) _ _ _ _ <;> simp_all +decide;
        · exact fun a ha₁ ha₂ => ⟨ segStarts_pred_mem BS H B ha₂ ha₁, a, ⟨ ha₁, ha₂ ⟩, rfl ⟩;
        · intro a₁ ha₁ ha₂ a₂ ha₃ ha₄ h; rw [ tsub_left_inj ] at h <;> linarith [ segStarts_le BS H B ha₂, segStarts_le BS H B ha₄, BS.hk0 ] ;
      rw [ h_split, ← Finset.prod_inter_mul_prod_diff ];
      refine' mul_le_mul _ _ _ _;
      any_goals exact H;
      · rw [ ← Finset.prod_inter_mul_prod_diff H ( ( H ∪ B ) ∩ image ( fun s => s - 1 ) ( ( segStarts BS H B ).erase BS.k0 ) ∩ H ) ];
        simp +decide [ Finset.inter_comm ];
        exact le_trans ( by rw [ Finset.prod_congr rfl fun x hx => if_pos <| Finset.mem_of_mem_inter_left hx ] ) ( le_mul_of_one_le_right ( Finset.prod_nonneg fun _ _ => Real.exp_nonneg _ ) <| le_trans ( by norm_num ) <| Finset.prod_le_prod ( fun _ _ => by positivity ) fun _ _ => Real.one_le_exp <| mul_nonneg heps <| hRwnn _ <| Finset.mem_sdiff.mp ‹_› |>.1 );
      · rw [ ← Finset.prod_sdiff <| show ( ( H ∪ B ) ∩ image ( fun s => s - 1 ) ( ( segStarts BS H B ).erase BS.k0 ) ) \ H ⊆ B from ?_ ];
        · rw [ Finset.prod_congr rfl fun x hx => if_neg <| by aesop ];
          exact le_mul_of_one_le_left ( Finset.prod_nonneg fun _ _ => Real.exp_nonneg _ ) ( by exact le_trans ( by norm_num ) ( Finset.prod_le_prod ( fun _ _ => by positivity ) fun _ _ => Real.one_le_exp ( mul_nonneg heps ( hPinn _ ( by aesop ) ) ) ) );
        · grind;
      · exact Finset.prod_nonneg fun x hx => by split_ifs <;> positivity;
      · exact Finset.prod_nonneg fun _ _ => Real.exp_nonneg _;
  by_cases h : BS.k0 ∈ segStarts BS H B <;> simp_all +decide [ mul_assoc ];
  · rw [ ← Finset.mul_prod_erase _ _ h ] ; exact mul_le_mul_of_nonneg_left h_erase <| Nat.cast_nonneg _;
  · exact le_trans h_erase ( le_mul_of_one_le_left ( mul_nonneg ( Finset.prod_nonneg fun _ _ => Real.exp_nonneg _ ) ( Finset.prod_nonneg fun _ _ => Real.exp_nonneg _ ) ) ( mod_cast Finset.card_pos.mpr ⟨ 0, by
      unfold labelFin; simp +decide [ L0 ] ;
      exact Int.ceil_nonneg ( div_nonneg ( mul_nonneg ( by norm_num ) ( Real.sqrt_nonneg _ ) ) ( sigmaP_nonneg _ ) ) ⟩ ) )

/-! ### N3 — per-fiber count discharge -/

/-
**N3 fiber discharge.**  Combining `hot_factor` (for hot blocks) and
    `cold_factor` (for cold blocks, with the segment-start label of size
    `≤ N·2^k/16`), every fiber's cardinality is at most the per-block product of
    `exp(2ε(v k + 1))`.  The label-size discharge is supplied as `hlabsize`.
-/

lemma cold_master_struct :
    ∃ (c2 e0 X0 : ℝ), 0 < c2 ∧ 0 < e0 ∧ 0 < X0 ∧
      (∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k → ¬ isHot BS c2 a k →
        SBEEForcing.IsDominant (2 ^ k) (BS.P k) (restrict BS a k) (1/4)) ∧
      (∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k < BS.K → X0 ≤ (2:ℝ) ^ k → k ∈ boundarySet BS c2 a →
        Pifloor BS e0 k ≤ Xen BS a k) := by
  obtain ⟨ c2, e0, X0, hc2, he0, hX0, h ⟩ := boundary_penalty_per_k;
  obtain ⟨X0thr, hX0thr⟩ : ∃ X0thr : ℕ, ∀ X : ℕ, X0thr ≤ X → 16 * e0 * Real.log X ≤ X := by
    have := SBEEForcing.exists_X0_const_logbnd ( 16 * e0 );
    exact ⟨ ⌈this.choose⌉₊, fun X hX => this.choose_spec.2 X <| Nat.le_of_ceil_le hX ⟩;
  refine' ⟨ c2, e0, Max.max X0 ( Max.max 16 X0thr ), hc2, he0, _, _, _ ⟩ <;> norm_num;
  · intro BS a k hk1 hk2 hk3 hk4 hk5 hk6
    obtain ⟨h_card, h_abs, h_res⟩ := h.left BS a k hk1 hk2 hk3 hk6
    have h_class_count : (classCount BS a k (coldLabel BS a k) : ℝ) ≥ (3 / 4 : ℝ) * (BS.P k).card := by
      have h_class_count : (classCount BS a k (coldLabel BS a k) : ℝ) ≥ (BS.P k).card - (excSet BS a k).card := by
        have h_class_count : (classCount BS a k (coldLabel BS a k) : ℝ) ≥ (BS.P k \ excSet BS a k).card := by
          rw [ conform_card_eq BS a k ( Finset.mem_Icc.mpr ⟨ hk1, hk2 ⟩ ) ];
        rw [ Finset.card_sdiff ] at h_class_count;
        rw [ Nat.cast_sub ] at h_class_count;
        · exact le_trans ( sub_le_sub_left ( Nat.cast_le.mpr <| Finset.card_mono <| Finset.inter_subset_left ) _ ) h_class_count;
        · exact Finset.card_le_card fun x hx => by aesop;
      have h_card_bound : (BS.P k).card ≥ (2 ^ k : ℝ) / (2 * Real.log (2 ^ k)) := by
        exact BS.hdensity k hk1 hk2;
      have := hX0thr ( 2 ^ k ) ( by exact_mod_cast hk5 ) ; norm_num at *;
      rw [ div_le_iff₀ ] at h_card_bound <;> nlinarith [ show ( k : ℝ ) * Real.log 2 > 0 by exact mul_pos ( Nat.cast_pos.mpr ( Nat.pos_of_ne_zero ( by rintro rfl; norm_num at hk4 ) ) ) ( Real.log_pos one_lt_two ) ]
    exact (by
    refine' ⟨ coldLabel BS a k, _, _ ⟩;
    · rw [ le_div_iff₀ ] at * <;> norm_cast at *;
      have h_card_le : (BS.P k).card ≤ 2 ^ k := by
        have h_card_le : (BS.P k).card ≤ Finset.card (Finset.Ico (2 ^ k) (2 ^ (k + 1))) := by
          exact Finset.card_le_card fun x hx => Finset.mem_Ico.mpr <| BS.hwindow k x hx;
        exact h_card_le.trans ( by norm_num [ pow_succ' ] ; linarith );
      rw [ Nat.le_iff_lt_or_eq ] at h_card_le ; norm_num at *;
      cases h_card_le <;> nlinarith [ Nat.div_add_mod ( ( 2 ^ k ) ^ 2 ) 2, Nat.mod_lt ( ( 2 ^ k ) ^ 2 ) two_pos ];
    · convert h_class_count.le using 1 ; norm_num [ classCount ]);
  · exact fun BS a k hk₁ hk₂ hk₃ hk₄ hk₅ hk₆ => h.2 BS a k hk₁ hk₂ hk₃ hk₆

/-
**Master cold constants** (with arbitrary-block-assignment cold dominance).
    Strengthens `cold_master_struct` by shrinking `c2` to also lie below
    Theorem-B's intrinsic constant, exposing `ColdDominance c2` in addition to
    the block dominance for restrictions and the boundary penalty floor.
-/

lemma cold_master :
    ∃ (c2 e0 X0 : ℝ), 0 < c2 ∧ 0 < e0 ∧ 0 < X0 ∧
      (∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k → ¬ isHot BS c2 a k →
        SBEEForcing.IsDominant (2 ^ k) (BS.P k) (restrict BS a k) (1/4)) ∧
      (∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k < BS.K → X0 ≤ (2:ℝ) ^ k → k ∈ boundarySet BS c2 a →
        Pifloor BS e0 k ≤ Xen BS a k) ∧
      ColdDominance c2 := by
  obtain ⟨c2P, e0, X0P, hc2P, he0, hX0P, hdomR, hpen⟩ := GlobalControl.cold_master_struct
  obtain ⟨c2B, X0B, hc2B, hX0B, HB⟩ := SBEEForcing.theorem_B_nondominant_forcing (1/4) (by norm_num) (by norm_num);
  refine' ⟨ Min.min c2P c2B, e0, Max.max X0P ( Max.max X0B 1 ), _, _, _, _, _, _ ⟩ <;> norm_num [ hc2P, he0, hX0P, hc2B, hX0B ];
  · intro BS a k hk1 hk2 hX0P hX0B h1 hnh;
    apply hdomR BS a k hk1 hk2 hX0P;
    exact not_isHot_mono_cold ( min_le_left _ _ ) ( le_of_lt ( lt_min hc2P hc2B ) ) BS a k hnh;
  · intro BS a k hk1 hk2 hX0P hX0B h1 hk; exact hpen BS a k hk1 hk2 hX0P ( boundarySet_mono ( min_le_left _ _ ) ( le_of_lt ( lt_min hc2P hc2B ) ) BS a hk ) ;
  · refine' ⟨ Max.max X0B 1, by positivity, _ ⟩;
    intro BS k hk1 hk2 hk3 b Rb hQ hRb;
    contrapose! HB;
    refine' ⟨ 2 ^ k, _, BS.P k, _, _, _, b, Rb, hQ, HB, _ ⟩ <;> norm_num at *;
    · linarith;
    · exact fun p hp => ⟨ Nat.Prime.ne_zero ( BS.hprime k p hp ) ⟩;
    · exact fun p hp => ⟨ BS.hprime k p hp, by linarith [ BS.hwindow k p hp ], by linarith [ BS.hwindow k p hp, pow_succ' ( 2 : ℕ ) k ] ⟩;
    · convert BS.hdensity k hk1 hk2 using 1 ; norm_num [ Real.log_pow ];
    · refine' lt_of_lt_of_le hRb _;
      convert Rw_mono_c2 ( min_le_right c2P c2B ) ( le_of_lt ( lt_min hc2P hc2B ) ) k using 1 ; norm_num [ Rw ]

/-
**Label admissibility (`hadmL`).**  For `k0` past a uniform threshold, the
    zero-extended cold labels of any sub-`R` assignment lie in `admLabels`.
    This routes `coldLabel_mem_labelFin` (needing `IsDominant` from `cold_master`)
    through every segment start.
-/

lemma hadmL_final (c2 X0 : ℝ) (hc2 : 0 < c2)
    (hdom : ∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k → ¬ isHot BS c2 a k →
        SBEEForcing.IsDominant (2 ^ k) (BS.P k) (restrict BS a k) (1/4)) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem), k0min ≤ BS.k0 → X0 ≤ (2:ℝ) ^ BS.k0 →
      ∀ (a : GlobalAssignment BS) (R : ℝ), 0 ≤ R → Qctrl BS a ≤ R →
        extLabel BS a (hotSet BS c2 a) (boundarySet BS c2 a)
          ∈ admLabels BS c2 R (hotSet BS c2 a) (boundarySet BS c2 a) := by
  -- Choose k0min such that for all s ≥ k0min, 16 ≤ 2^s, 8 ≤ (BS.P s).card, and 1 ≤ Real.log (2^s).
  obtain ⟨k0min, hk0min⟩ : ∃ k0min : ℕ, ∀ s : ℕ, k0min ≤ s →
      16 ≤ (2:ℕ) ^ s ∧ 8 ≤ (2 ^ s / (2 * Real.log (2 ^ s))) := by
        refine' ⟨ 16, fun s hs => ⟨ _, _ ⟩ ⟩;
        · exact le_trans ( by norm_num ) ( pow_le_pow_right₀ ( by norm_num ) hs );
        · rw [ le_div_iff₀ ( by exact mul_pos zero_lt_two ( Real.log_pos ( one_lt_pow₀ one_lt_two ( by linarith ) ) ) ) ];
          induction hs <;> norm_num [ pow_succ' ] at *;
          · rw [ show ( 65536 : ℝ ) = 2 ^ 16 by norm_num, Real.log_pow ] ; norm_num ; linarith [ Real.log_le_sub_one_of_pos zero_lt_two ];
          · rw [ Real.log_mul ( by positivity ) ( by positivity ), Real.log_pow ];
            nlinarith [ Real.log_le_sub_one_of_pos zero_lt_two, Real.log_pos one_lt_two, ( by norm_cast : ( 16 : ℝ ) ≤ ↑‹ℕ› ), pow_le_pow_right₀ ( by norm_num : ( 1 : ℝ ) ≤ 2 ) ‹16 ≤ _› ];
  use k0min;
  intro BS hBS hX0 a R hR0 hR1;
  apply extLabel_mem_admLabels;
  intro s hs
  have hs1 : BS.k0 ≤ s := by
    exact segStarts_le BS _ _ hs |>.1
  have hs2 : s ≤ BS.K := by
    exact segStarts_le BS _ _ hs |>.2
  have hslog : 1 ≤ Real.log (2 ^ s) := by
    rw [ Real.le_log_iff_exp_le ( by positivity ) ];
    exact le_trans ( Real.exp_one_lt_d9.le ) ( by norm_num; linarith [ show ( 2 : ℝ ) ^ s ≥ 16 by exact_mod_cast hk0min s ( by linarith ) |>.1 ] )
  have hN8 : 8 ≤ (BS.P s).card := by
    have := BS.hdensity s ( by linarith ) ( by linarith );
    exact_mod_cast this.trans' ( hk0min s ( by linarith ) |>.2 )
  have hσpos : 0 < sigmaP (BS.P s) := by
    apply sigmaP_pos_of_two;
    · exact fun p hp => BS.hprime s p hp;
    · linarith
  have hbR : blockEnergy BS a s ≤ R := by
    exact le_trans ( Finset.single_le_sum ( fun k _ => QP_nonneg ( BS.P k ) ( restrict BS a k ) ) ( Finset.mem_Icc.mpr ⟨ hs1, hs2 ⟩ ) ) ( sum_blockEnergy_le BS a R hR1 )
  have hcold : ¬ isHot BS c2 a s := by
    have := Finset.mem_filter.mp hs; simp_all +decide [ Finset.mem_sdiff ] ;
    exact fun h => this.1 <| Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ hs1, hs2 ⟩, h ⟩
  have hdomk : SBEEForcing.IsDominant (2 ^ s) (BS.P s) (restrict BS a s) (1 / 4) := by
    exact hdom BS a s hs1 hs2 ( by exact le_trans hX0 ( pow_le_pow_right₀ ( by norm_num ) hs1 ) ) hcold;
  apply coldLabel_mem_labelFin BS c2 R a s hs1 hs2 hR0 hc2.le (hk0min s (by linarith)).left hN8 hslog hdomk hcold hbR hσpos

/-
**Control deviation positivity.**  When `BS.k0 ≥ 2` the block `P_{k0}` has
    at least two primes (block density), so the internal control pairs of the
    `k0` block are nonempty and `sigmaCtrl BS > 0`.
-/

lemma sigmaCtrl_pos_of_k0 (BS : BlockSystem) (hk0 : 2 ≤ BS.k0) : 0 < sigmaCtrl BS := by
  refine' Real.sqrt_pos.mpr _;
  obtain ⟨p, q, hpq⟩ : ∃ p q : ℕ, p ∈ BS.P BS.k0 ∧ q ∈ BS.P BS.k0 ∧ p < q := by
    have h_card : 2 ≤ (BS.P BS.k0).card := by
      have := BS.hdensity BS.k0 ( by norm_num ) ( by linarith [ BS.hk ] );
      rw [ div_le_iff₀ ] at this <;> norm_num at *;
      · contrapose! this;
        interval_cases _ : Finset.card ( BS.P BS.k0 ) <;> norm_num at *;
        rcases n : BS.k0 with ( _ | _ | _ | k ) <;> simp_all +decide [ pow_succ' ];
        · exact Real.log_two_lt_d9.trans_le ( by norm_num );
        · exact Nat.recOn k ( by norm_num; have := Real.log_two_lt_d9; norm_num1 at *; linarith ) fun n ihn => by norm_num [ pow_succ' ] at * ; nlinarith [ Real.log_le_sub_one_of_pos zero_lt_two, Real.log_pos one_lt_two ] ;
      · positivity;
    obtain ⟨ p, hp, q, hq, hpq ⟩ := Finset.one_lt_card.mp h_card; cases lt_trichotomy p q <;> aesop;
  refine' lt_of_lt_of_le _ ( Finset.single_le_sum ( fun x _ => by positivity ) ( show ( p, q ) ∈ ctrlPairs BS from _ ) ) <;> norm_num [ hpq ];
  · exact sq_pos_of_pos ( mul_pos ( Nat.cast_pos.mpr ( Nat.Prime.pos ( by have := BS.hprime BS.k0; aesop ) ) ) ( Nat.cast_pos.mpr ( Nat.Prime.pos ( by have := BS.hprime BS.k0; aesop ) ) ) );
  · exact Finset.mem_union_left _ ( Finset.mem_biUnion.mpr ⟨ BS.k0, Finset.mem_Icc.mpr ⟨ le_rfl, by linarith [ BS.hk ] ⟩, Finset.mem_filter.mpr ⟨ Finset.mem_product.mpr ⟨ hpq.1, hpq.2.1 ⟩, hpq.2.2 ⟩ ⟩ )

/-
**Boundary floor lower bound.**  Past a uniform threshold, the boundary
    Peierls floor `Pifloor BS e0 (s-1)` dominates `2^{s-1}/log(2^{s-1})^3`
    (the `Rw`-shaped quantity).  Uses the block density `N_k ≥ 2^k/(2 log 2^k)`:
    `Pifloor ≈ N_s·N_{s-1}^3/(2^13·2^{2(s-1)}) ≈ 2^{2s}/poly`, with the extra
    `~2^s/log` factor overtaking any fixed multiple of `2^{s-1}/log^3`.
-/

lemma Pifloor_charge_lower (e0 : ℝ) (he0 : 0 < e0) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem) (s : ℕ), k0min ≤ s →
      BS.k0 + 1 ≤ s → s ≤ BS.K →
      (2:ℝ) ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3 ≤ Pifloor BS e0 (s - 1) := by
  have h_tendsto : Filter.Tendsto (fun n : ℕ => (2 : ℝ) ^ (n - 1) / (Real.log (2 ^ (n - 1))) ^ 3) Filter.atTop Filter.atTop := by
    -- We can use the fact that $2^{n-1} / (\log(2^{n-1}))^3$ grows exponentially faster than any polynomial function.
    have h_exp_growth : Filter.Tendsto (fun n : ℕ => (2 : ℝ) ^ n / (n * Real.log 2) ^ 3) Filter.atTop Filter.atTop := by
      -- We can factor out $2^n$ and use the fact that $\frac{1}{n^3}$ tends to $0$ as $n$ tends to infinity.
      suffices h_factor : Filter.Tendsto (fun n : ℕ => (2 : ℝ) ^ n / n ^ 3) Filter.atTop Filter.atTop by
        convert h_factor.const_mul_atTop ( show 0 < ( Real.log 2 ) ⁻¹ ^ 3 by positivity ) using 2 ; ring;
      -- We can convert this limit into a form that is easier to handle by substituting $m = n \log 2$.
      suffices h_log : Filter.Tendsto (fun m : ℝ => Real.exp m / (m / Real.log 2) ^ 3) Filter.atTop Filter.atTop by
        convert h_log.comp ( tendsto_natCast_atTop_atTop.atTop_mul_const ( Real.log_pos one_lt_two ) ) using 2 ; norm_num [ Real.exp_nat_mul, Real.exp_log ];
      ring_nf;
      exact Filter.Tendsto.atTop_mul_const ( by positivity ) ( by simpa using Real.tendsto_exp_div_pow_atTop 3 );
    convert h_exp_growth.comp ( Filter.tendsto_sub_atTop_nat 1 ) using 2 ; norm_num [ Real.log_pow ];
  obtain ⟨k0min, hk0min⟩ : ∃ k0min : ℕ, ∀ s ≥ k0min, (2 : ℝ) ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3 ≤ (2 ^ s / (4 * Real.log (2 ^ s))) * (2 ^ (s - 1) / (4 * Real.log (2 ^ (s - 1)))) ^ 3 / (2 ^ 13 * (2 ^ (s - 1)) ^ 2) := by
    have h_tendsto : Filter.Tendsto (fun n : ℕ => (2 ^ n / (4 * Real.log (2 ^ n))) * (2 ^ (n - 1) / (4 * Real.log (2 ^ (n - 1)))) ^ 3 / (2 ^ 13 * (2 ^ (n - 1)) ^ 2) / (2 ^ (n - 1) / (Real.log (2 ^ (n - 1))) ^ 3)) Filter.atTop Filter.atTop := by
      -- Simplify the expression inside the limit.
      suffices h_simplify : Filter.Tendsto (fun n : ℕ => (2 ^ n / (4 * n * Real.log 2)) * (2 ^ (3 * (n - 1)) / (64 * (n - 1) ^ 3 * (Real.log 2) ^ 3)) / (2 ^ 13 * 2 ^ (2 * (n - 1))) / (2 ^ (n - 1) / ((n - 1) ^ 3 * (Real.log 2) ^ 3))) Filter.atTop Filter.atTop by
        convert h_simplify using 2 ; norm_num [ Real.log_pow ] ; ring;
        cases ‹ℕ› <;> norm_num ; ring;
      -- Simplify the expression inside the limit further.
      suffices h_simplify' : Filter.Tendsto (fun n : ℕ => (2 ^ n * 2 ^ (3 * (n - 1))) / (4 * n * 64 * 2 ^ 13 * 2 ^ (2 * (n - 1)) * 2 ^ (n - 1)) * (1 / (Real.log 2))) Filter.atTop Filter.atTop by
        refine h_simplify'.congr' ?_;
        filter_upwards [ Filter.eventually_gt_atTop 1 ] with n hn;
        field_simp;
        rw [ div_self ( sub_ne_zero_of_ne ( by norm_cast; linarith ) ) ];
      -- Simplify the expression inside the limit further by cancelling out common terms.
      suffices h_simplify'' : Filter.Tendsto (fun n : ℕ => (2 ^ (n + 3 * (n - 1) - 2 * (n - 1) - (n - 1))) / (4 * n * 64 * 2 ^ 13) * (1 / Real.log 2)) Filter.atTop Filter.atTop by
        refine h_simplify''.congr' ?_;
        filter_upwards [ Filter.eventually_gt_atTop 1 ] with n hn;
        rw [ show n + 3 * ( n - 1 ) - 2 * ( n - 1 ) - ( n - 1 ) = n by omega ] ; ring;
        norm_num [ mul_assoc, mul_comm, mul_left_comm, ← mul_pow ];
        norm_num [ ← mul_assoc, ← mul_pow ];
      -- Simplify the exponent in the numerator.
      suffices h_exp : Filter.Tendsto (fun n : ℕ => (2 ^ n : ℝ) / (4 * n * 64 * 2 ^ 13) * (1 / Real.log 2)) Filter.atTop Filter.atTop by
        refine h_exp.congr' ( by filter_upwards [ Filter.eventually_gt_atTop 1 ] with n hn; rw [ show n + 3 * ( n - 1 ) - 2 * ( n - 1 ) - ( n - 1 ) = n by omega ] );
      -- We can factor out the constant $1 / (4 * 64 * 2 ^ 13 * \log 2)$ from the limit.
      suffices h_factor : Filter.Tendsto (fun n : ℕ => (2 ^ n : ℝ) / n) Filter.atTop Filter.atTop by
        convert h_factor.const_mul_atTop ( show 0 < ( 1 / ( 4 * 64 * 2 ^ 13 * Real.log 2 ) ) by positivity ) using 2 ; ring;
      have h_exp_growth : Filter.Tendsto (fun n : ℕ => (Real.exp (n * Real.log 2)) / (n : ℝ)) Filter.atTop Filter.atTop := by
        have := Real.tendsto_exp_div_pow_atTop 1;
        have := this.comp ( tendsto_natCast_atTop_atTop.atTop_mul_const ( Real.log_pos one_lt_two ) );
        convert this.const_mul_atTop ( show 0 < Real.log 2 by positivity ) using 2 ; norm_num ; ring;
        norm_num [ mul_assoc, mul_comm, mul_left_comm ];
      simpa [ Real.exp_nat_mul, Real.exp_log ] using h_exp_growth;
    have := h_tendsto.eventually_gt_atTop 1;
    rw [ Filter.eventually_atTop ] at this; rcases this with ⟨ k0min, hk0min ⟩ ; exact ⟨ k0min + 2, fun s hs => by have := hk0min s ( by linarith ) ; rw [ lt_div_iff₀ ( by exact div_pos ( pow_pos ( by positivity ) _ ) ( pow_pos ( Real.log_pos ( one_lt_pow₀ ( by norm_num ) ( by omega ) ) ) _ ) ) ] at this; linarith ⟩ ;
  obtain ⟨k0min', hk0min'⟩ : ∃ k0min' : ℕ, ∀ s ≥ k0min', ∀ BS : BlockSystem, s ∈ Finset.Icc BS.k0 BS.K → (2 : ℝ) ^ s / (2 * Real.log (2 ^ s)) ≥ 2 * e0 + 2 ∧ (2 : ℝ) ^ (s - 1) / (2 * Real.log (2 ^ (s - 1))) ≥ 2 * e0 + 2 := by
    have h_tendsto : Filter.Tendsto (fun n : ℕ => (2 : ℝ) ^ n / (2 * Real.log (2 ^ n))) Filter.atTop Filter.atTop := by
      norm_num [ Real.log_pow ];
      -- We can factor out the constant $1/(2 \log 2)$ and use the fact that $2^n / n$ tends to infinity.
      have h_factor : Filter.Tendsto (fun n : ℕ => (2 : ℝ) ^ n / n) Filter.atTop Filter.atTop := by
        have h_exp_growth : Filter.Tendsto (fun n : ℕ => (Real.exp (n * Real.log 2)) / n) Filter.atTop Filter.atTop := by
          have := Real.tendsto_exp_div_pow_atTop 1;
          have := this.comp ( tendsto_natCast_atTop_atTop.atTop_mul_const ( Real.log_pos one_lt_two ) );
          convert this.const_mul_atTop ( show 0 < Real.log 2 by positivity ) using 2 ; norm_num ; ring;
          norm_num [ mul_assoc, mul_comm, mul_left_comm ];
        simpa [ Real.exp_nat_mul, Real.exp_log ] using h_exp_growth;
      convert h_factor.const_mul_atTop ( show 0 < ( 1 / ( 2 * Real.log 2 ) ) by positivity ) using 2 ; ring;
    exact Filter.eventually_atTop.mp ( h_tendsto.eventually_ge_atTop ( 2 * e0 + 2 ) ) |> fun ⟨ k0min', hk0min' ⟩ ↦ ⟨ k0min' + 1, fun s hs BS hBS ↦ ⟨ hk0min' s ( by linarith ), hk0min' ( s - 1 ) ( Nat.le_sub_one_of_lt ( by linarith ) ) ⟩ ⟩;
  use k0min' + k0min + 1;
  intros BS s hs hs' hs''; specialize hk0min s ( by linarith ) ; specialize hk0min' s ( by linarith ) BS ( Finset.mem_Icc.mpr ⟨ by linarith, by linarith ⟩ ) ; simp_all +decide [ Pifloor ] ;
  refine le_trans hk0min ?_;
  gcongr;
  · have := BS.hdensity ( s - 1 + 1 ) ( by omega ) ( by omega ) ; simp_all +decide [ Nat.sub_add_cancel ( by linarith : 1 ≤ s ) ] ;
    grind;
  · rw [ Nat.sub_add_cancel ( by linarith ) ];
    have := BS.hdensity s ( by linarith ) ( by linarith );
    norm_num [ Real.log_pow ] at * ; ring_nf at * ; linarith;
  · have := BS.hdensity ( s - 1 ) ( by omega ) ( by omega ) ; simp_all +decide [ div_le_iff₀ ] ;
    ring_nf at *; linarith;

/-
**N1 boundary charge.**  For a segment start `s` past a uniform threshold,
    the label-window size `2·labelBound c2 s + 1` is dominated by the boundary
    Peierls floor `Pifloor BS e0 (s-1)` of the predecessor boundary block `s-1`.
    Companion to `labelBound_charge_hot`, combining `Pifloor_charge_lower` with
    `pow_beats_poly_log` exactly as in `labelBound_charge_hot`.
-/

lemma labelBound_charge_boundary (c2 e0 eps : ℝ)
    (heps : 0 < eps) (hc2 : 0 < c2) (he0 : 0 < e0) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem) (s : ℕ), k0min ≤ s →
      BS.k0 + 1 ≤ s → s ≤ BS.K →
      (2 * (labelBound c2 s : ℝ) + 1) ≤ Real.exp (eps * Pifloor BS e0 (s - 1)) := by
  -- Apply `pow_beats_poly_log` to obtain `N1` and `N2`.
  obtain ⟨N1, hN1⟩ : ∃ N1 : ℕ, ∀ s : ℕ, N1 ≤ s →
    (640 / 3) * Real.sqrt (c2 * (2:ℝ) ^ s) * ((2:ℝ) ^ s * Real.log (2 ^ s)) + 3 ≤
      Real.exp (Real.log ((640 / 3) * Real.sqrt (c2 * (2:ℝ) ^ s) * ((2:ℝ) ^ s * Real.log (2 ^ s))) + 1) := by
        have hN1 : ∃ N1 : ℕ, ∀ s : ℕ, N1 ≤ s →
          (640 / 3) * Real.sqrt (c2 * (2:ℝ) ^ s) * ((2:ℝ) ^ s * Real.log (2 ^ s)) ≥ 3 := by
            have hN1 : Filter.Tendsto (fun s : ℕ => (640 / 3) * Real.sqrt (c2 * (2:ℝ) ^ s) * ((2:ℝ) ^ s * Real.log (2 ^ s))) Filter.atTop Filter.atTop := by
              norm_num [ Real.log_rpow ];
              refine' Filter.Tendsto.atTop_mul_atTop₀ _ _;
              · exact Filter.Tendsto.const_mul_atTop ( by positivity ) ( Filter.Tendsto.const_mul_atTop ( by positivity ) ( by simpa only [ Real.sqrt_eq_rpow ] using tendsto_rpow_atTop ( by positivity ) |> Filter.Tendsto.comp <| tendsto_pow_atTop_atTop_of_one_lt one_lt_two ) );
              · exact Filter.Tendsto.atTop_mul_atTop₀ ( tendsto_pow_atTop_atTop_of_one_lt one_lt_two ) ( Filter.Tendsto.atTop_mul_const ( by positivity ) tendsto_natCast_atTop_atTop );
            exact Filter.eventually_atTop.mp ( hN1.eventually_ge_atTop 3 );
        obtain ⟨ N1, hN1 ⟩ := hN1; use N1; intro s hs; rw [ Real.exp_add, Real.exp_log ( by linarith [ hN1 s hs ] ) ] ; nlinarith [ hN1 s hs, Real.add_one_le_exp 1 ] ;
  obtain ⟨N2, hN2⟩ : ∃ N2 : ℕ, ∀ s : ℕ, N2 ≤ s →
    Real.log ((640 / 3) * Real.sqrt (c2 * (2:ℝ) ^ s) * ((2:ℝ) ^ s * Real.log (2 ^ s))) + 1 ≤
      eps * (2:ℝ) ^ (s - 1) / (Real.log (2 ^ (s - 1))) ^ 3 := by
        obtain ⟨ N2, hN2 ⟩ := pow_beats_poly_log ( Real.log ( 640 / 3 * Real.sqrt c2 ) + 2 ) ( eps ) ( by positivity );
        use N2 + 4; intros s hs; specialize hN2 s ( by linarith ) ; simp_all +decide [ Real.log_mul, Real.log_sqrt, ne_of_gt ] ;
        rw [ Real.log_mul, Real.log_mul, Real.log_mul, Real.log_mul, Real.log_sqrt, Real.log_sqrt ] <;> try positivity;
        · rw [ Real.log_sqrt ( by positivity ) ] at hN2 ; norm_num [ Real.log_pow ] at * ; linarith;
        · exact ne_of_gt ( mul_pos ( Nat.cast_pos.mpr ( by linarith ) ) ( Real.log_pos ( by norm_num ) ) );
        · exact ne_of_gt ( mul_pos ( pow_pos ( by norm_num ) _ ) ( mul_pos ( Nat.cast_pos.mpr ( by linarith ) ) ( Real.log_pos ( by norm_num ) ) ) );
  obtain ⟨kP, hkP⟩ := Pifloor_charge_lower e0 he0;
  refine' ⟨ Max.max N1 ( Max.max N2 ( Max.max kP 4 ) ), fun BS s hs hs' hs'' => _ ⟩ ; simp_all +decide [ labelBound ];
  refine' le_trans _ ( Real.exp_le_exp.mpr ( le_trans _ ( mul_le_mul_of_nonneg_left ( hkP BS s hs.2.2.1 hs' hs'' ) heps.le ) ) );
  convert hN1 s hs.1 |> le_trans _ using 1;
  · linarith [ Int.ceil_lt_add_one ( 20 / 3 * ( Real.sqrt c2 * Real.sqrt ( 2 ^ s ) ) * ( 16 * 2 ^ s * ( s * Real.log 2 ) ) ) ];
  · convert hN2 s hs.2.1 using 1 ; ring

/-
Block cardinality lower bound: past a uniform `2^k` threshold the block
    density forces `8 ≤ (BS.P k).card`.  (`2^k/(2 log 2^k) → ∞`.)
-/

lemma cold_small_label_agree (c2 : ℝ) (hc2 : 0 < c2) (hdomB : ColdDominance c2) :
    ∃ (e0 X0 : ℝ), 0 < e0 ∧ 0 < X0 ∧
      ∀ (BS : BlockSystem) (k : ℕ), BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k →
        ∀ (m : ℤ) (n : ℕ), (n : ℝ) + 1 < Rw c2 k →
        ∀ (b : BlockAssignment (BS.P k)),
          QP (BS.P k) b ≤ (n : ℝ) + 1 →
          (1 - (1/4 : ℝ)) * ((BS.P k).card : ℝ) ≤
            (((BS.P k).attach.filter (fun p => b p = ((m : ℤ) : ZMod (p : ℕ)))).card : ℝ) →
          ∃ mb : ℤ,
            |(mb : ℝ)| ≤ ((BS.P k).card : ℝ) * (2 ^ k) / 16 ∧
            (1 - (1/4 : ℝ)) * ((BS.P k).card : ℝ) ≤
              (((BS.P k).attach.filter (fun p => b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) ∧
            (3/4 : ℝ) * ((BS.P k).card : ℝ) - e0 ≤
              (((BS.P k).attach.filter
                (fun (p : {x // x ∈ BS.P k}) =>
                  ((m : ℤ) : ZMod (p : ℕ)) = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) := by
  obtain ⟨X1, hX1pos, hdom⟩ := hdomB;
  obtain ⟨X0s, hX0s0, Hsize⟩ := SBEEForcing.cold_label_size (1/4) (by norm_num) (by norm_num) c2 hc2
  obtain ⟨e0, X0e, he0pos, hX0e0, Hexc⟩ := SBEEForcing.cold_exception_bound (1/4) (by norm_num) (by norm_num) c2 hc2;
  refine' ⟨ e0, Max.max X1 ( Max.max X0s ( Max.max X0e 16 ) ), he0pos, _, _ ⟩ <;> norm_num;
  intro BS k hk1 hk2 hk3 hk4 hk5 hk6 m n hn b hQ hconf
  obtain ⟨mb, hmb_abs, hmb_conf⟩ := hdom BS k hk1 hk2 hk3 b ((n:ℝ)+1) hQ hn
  refine' ⟨mb, _, _, _⟩;
  · convert Hsize ( 2 ^ k ) ( mod_cast hk4 ) ( BS.P k ) _ _ b mb ( n + 1 ) _ _ _ _ using 1 <;> norm_num;
    any_goals assumption;
    · exact Or.inl <| le_of_lt <| by simpa [ Rw ] using hn;
    · exact fun p hp => ⟨ BS.hprime k p hp, BS.hwindow k p hp |>.1, by linarith [ BS.hwindow k p hp |>.2, pow_succ' ( 2 : ℕ ) k ] ⟩;
    · convert BS.hdensity k hk1 hk2 using 1 ; norm_num [ Real.log_pow ];
    · linarith;
  · linarith;
  · have hmb_small : |(mb : ℝ)| ≤ ((BS.P k).card : ℝ) * (2 ^ k) / 16 := by
      convert Hsize ( 2 ^ k ) _ ( BS.P k ) _ _ b mb ( n + 1 ) _ _ _ _ using 1 <;> norm_num;
      any_goals assumption;
      · exact Or.inl <| le_of_lt <| by simpa [ Rw ] using hn;
      · exact fun p hp => ⟨ BS.hprime k p hp, by linarith [ BS.hwindow k p hp ], by linarith [ BS.hwindow k p hp, pow_succ' ( 2 : ℕ ) k ] ⟩;
      · convert BS.hdensity k hk1 hk2 using 1 ; ring;
        norm_num [ Real.log_pow ] ; ring;
      · grind +revert;
    have hmb_small : ((Finset.univ.filter (fun q : {x // x ∈ BS.P k} => b q ≠ ((mb : ℤ) : ZMod (q : ℕ)))).card : ℝ) ≤ e0 := by
      convert Hexc ( 2 ^ k ) ( mod_cast hk5 ) ( BS.P k ) _ _ b mb ( n + 1 ) _ _ _ _ _ using 1 <;> norm_num;
      any_goals linarith;
      · exact fun p hp => ⟨ BS.hprime k p hp, by linarith [ BS.hwindow k p hp ], by linarith [ BS.hwindow k p hp, pow_succ' ( 2 : ℕ ) k ] ⟩;
      · have := BS.hdensity k hk1 hk2;
        simpa [ Real.log_pow ] using this;
      · convert hn.le using 1;
        unfold Rw; norm_num [ Real.log_pow ] ;
    have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) ≥ ((BS.P k).card : ℝ) - e0 := by
      have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) + ((Finset.univ.filter (fun q : {x // x ∈ BS.P k} => b q ≠ ((mb : ℤ) : ZMod (q : ℕ)))).card : ℝ) = (BS.P k).card := by
        rw_mod_cast [ Finset.card_filter_add_card_filter_not ];
        simp +decide [ Finset.card_univ ];
      linarith;
    have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)) ∧ b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) ≥ ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)))).card : ℝ) + ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) - ((BS.P k).card : ℝ) := by
      have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)) ∨ b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) ≤ ((BS.P k).card : ℝ) := by
        exact_mod_cast le_trans ( Finset.card_le_univ _ ) ( by norm_num );
      have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)) ∨ b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) = ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)))).card : ℝ) + ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) - ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)) ∧ b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) := by
        rw [ ← Nat.cast_add, ← Finset.card_union_add_card_inter ];
        simp +decide [ Finset.filter_or, Finset.filter_and ];
      linarith;
    have hmb_small : ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => b p = ((m : ℤ) : ZMod (p : ℕ)) ∧ b p = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) ≤ ((Finset.univ.filter (fun p : {x // x ∈ BS.P k} => ((m : ℤ) : ZMod (p : ℕ)) = ((mb : ℤ) : ZMod (p : ℕ)))).card : ℝ) := by
      gcongr;
      exact fun h => h.1.symm.trans h.2;
    linarith!

/-- **Wrapped-label reduction kernel (note 45).**
    In the low-energy wrapped regime, the assignments conforming to a large
    wrapped label `m` inject into the fixed-label fiber for one small label `M`.
    This is the Theorem-A-internal dominant-representative extraction and
    transport step; with it, `cold_count_wrap` is just `cold_factor`.  The cold
    dominance for arbitrary block assignments is supplied via `hdomB`. -/

lemma Pifloor_nonneg (e0 : ℝ) (he0 : 0 < e0) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem) (j : ℕ), k0min ≤ j → BS.k0 ≤ j → j < BS.K →
      0 ≤ Pifloor BS e0 j := by
  -- Choose `k0min` so that for `j ≥ k0min`, the densities force both parts to be nonnegative.
  have h_tendsto : Filter.Tendsto (fun k : ℕ => (2 ^ k : ℝ) / (2 * Real.log (2 ^ k))) Filter.atTop Filter.atTop := by
    norm_num [ Real.log_rpow ];
    -- We can use the fact that $2^k / k$ grows exponentially faster than $k$.
    have h_exp_growth : Filter.Tendsto (fun k : ℕ => (2 : ℝ) ^ k / k) Filter.atTop Filter.atTop := by
      refine' Filter.tendsto_atTop_mono' _ _ tendsto_natCast_atTop_atTop;
      filter_upwards [ Filter.eventually_gt_atTop 4 ] with k hk using by rw [ le_div_iff₀ ( by positivity ) ] ; norm_cast; induction hk <;> norm_num [ Nat.pow_succ ] at * ; nlinarith;
    convert h_exp_growth.const_mul_atTop ( show 0 < ( 1 / ( 2 * Real.log 2 ) ) by positivity ) using 2 ; ring;
  obtain ⟨ k0min, hk0min ⟩ := Filter.eventually_atTop.mp ( h_tendsto.eventually ( Filter.eventually_ge_atTop ( e0 + 2 ) ) );
  refine' ⟨ k0min, fun BS j hj hj' hj'' => _ ⟩;
  refine' div_nonneg _ _ <;> norm_num;
  refine' mul_nonneg _ ( pow_nonneg _ _ );
  · have := hk0min ( j + 1 ) ( by linarith );
    have := BS.hdensity ( j + 1 ) ( by linarith ) ( by linarith ) ; norm_num at * ; linarith;
  · have := BS.hdensity j hj' ( by linarith );
    linarith [ hk0min j hj ]

/-
Charge sum over admissible hot sets: `∑_H ∏_{j∈H} exp(ε·Rw j) ≤ exp(2εR)·exp(nB)`.
    `admH` is exactly the `Icc`-powerset filtered by `∑ Rw ≤ R`, so this is a
    direct instance of `sum_subset_charge_le` (with `Rw ≥ 0`).
-/

lemma chargeB_le (eps e0 : ℝ) (heps : 0 < eps) (he0 : 0 < e0) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem), k0min ≤ BS.k0 → ∀ R : ℝ,
      (∑ B ∈ admB BS e0 R, ∏ j ∈ B, Real.exp (eps * Pifloor BS e0 j))
        ≤ Real.exp (2 * eps * R) * Real.exp (numBlocks BS) := by
  -- Apply `Pifloor_nonneg` to find `kP` such that for all `j ≥ kP`, `Pifloor BS e0 j ≥ 0`.
  obtain ⟨kP, hkP⟩ : ∃ kP : ℕ, ∀ (BS : BlockSystem) (j : ℕ), kP ≤ j → BS.k0 ≤ j → j < BS.K → 0 ≤ Pifloor BS e0 j :=
    Pifloor_nonneg e0 he0
  use kP; intros BS hBS R; simp_all +decide [ admB ] ;
  refine' le_trans _ ( GlobalControl.sum_subset_charge_le BS ( fun j => if j < BS.K then Pifloor BS e0 j else 0 ) R eps heps _ );
  · refine' le_trans _ ( Finset.sum_le_sum_of_subset_of_nonneg _ _ );
    rotate_left;
    exact Finset.image ( fun B => B ) ( Finset.filter ( fun B => ∑ j ∈ B, Pifloor BS e0 j ≤ R ) ( Finset.powerset ( Finset.Ico BS.k0 BS.K ) ) );
    · simp +contextual [ Finset.subset_iff ];
      exact fun x hx₁ hx₂ y hy => le_of_lt ( hx₁ hy |>.2 );
    · exact fun _ _ _ => Finset.prod_nonneg fun _ _ => Real.exp_nonneg _;
    · simp +zetaDelta at *;
      exact Finset.sum_le_sum fun x hx => Finset.prod_le_prod ( fun _ _ => Real.exp_nonneg _ ) fun y hy => by rw [ if_pos ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_powerset.mp ( Finset.mem_filter.mp hx |>.1 ) hy ) ] ) ] ;
  · grind

/-
The initial label window cardinality is bounded by `3 + 14·√R/σ_{k0}`.
    `labelFin` at `k0` is `Icc (-(L0)) (L0)` with `L0 = ⌈7√R/σ_{k0}⌉ ≥ 0`, so its
    card is `2·L0 + 1 ≤ 2(7√R/σ_{k0} + 1) + 1`.
-/

lemma labelFin_k0_card_le (BS : BlockSystem) (c2 R : ℝ) (hR0 : 0 ≤ R) :
    ((labelFin BS c2 R BS.k0).card : ℝ) ≤ 3 + 14 * Real.sqrt R / sigmaP (BS.P BS.k0) := by
  -- Let `σ := sigmaP (BS.P BS.k0) ≥ 0` and `x := 7 * Real.sqrt R / σ ≥ 0`.
  set σ := sigmaP (BS.P BS.k0)
  have hσ0 : 0 ≤ σ := sigmaP_nonneg _
  set x := 7 * Real.sqrt R / σ
  have hx0 : 0 ≤ x := by
    positivity;
  --Card of an integer `Finset.Icc a b` is `(b - a + 1).toNat`; here `Finset.Icc (-(L0)) (L0)` has card `(L0 - (-(L0)) + 1).toNat = (2*L0 + 1).toNat`.
  have hlabels_card : ((labelFin BS c2 R BS.k0).card : ℝ) = 2 * Int.ceil x + 1 := by
    unfold labelFin; norm_num;
    rw [ show L0 BS R = ⌈x⌉ from rfl ] ; ring;
    norm_cast;
    rw [ Int.toNat_of_nonneg ( by positivity ) ];
  convert hlabels_card.le.trans _ using 1 ; ring;
  convert add_le_add_left ( mul_le_mul_of_nonneg_right ( Int.ceil_lt_add_one x |> le_of_lt ) zero_le_two ) 1 using 1 ; ring;
  ring!

/-
The per-segment-start label charge (`hcharge` for `label_product_le`):
    every non-initial window `|labelFin s|` is bounded by the predecessor's
    Peierls charge, via `labelBound_charge_hot` / `labelBound_charge_boundary`.
-/

lemma hrhs_charge_bound (eps c2 e0 : ℝ) (heps : 0 < eps) (heps1 : eps < 1)
    (hc2 : 0 < c2) (he0 : 0 < e0) (hdomB : ColdDominance c2) :
    ∃ k0min : ℕ, ∀ (BS : BlockSystem), k0min ≤ BS.k0 → ∀ R : ℝ, 0 ≤ R →
      (∑ H ∈ admH BS c2 R, ∑ B ∈ admB BS e0 R, ∑ v ∈ admShells BS c2 R H,
        ∑ ℓ ∈ admLabels BS c2 R H B, (fiber BS H B v ℓ).card : ℝ) ≤
        ((labelFin BS c2 R BS.k0).card : ℝ)
          * (Real.exp ((2 * eps + eps) * R) *
              Real.exp ((numBlocks BS : ℝ) *
                (2 * eps + Real.log (1 / (1 - Real.exp (-eps))))))
          * (Real.exp (2 * eps * R) * Real.exp (numBlocks BS))
          * (Real.exp (2 * eps * R) * Real.exp (numBlocks BS)) := by
  obtain ⟨Xf, hXf0, hfib⟩ := fiber_card_exp_bound' eps heps heps1 c2 hc2 hdomB;
  obtain ⟨kf, hkf⟩ : ∃ kf : ℕ, Xf ≤ 2 ^ kf := by
    exact pow_unbounded_of_one_lt Xf one_lt_two |> fun ⟨ kf, hkf ⟩ => ⟨ kf, le_of_lt hkf ⟩
  obtain ⟨kh, hchg⟩ := hcharge_le eps c2 e0 heps hc2 he0
  obtain ⟨kb, hchB⟩ := chargeB_le eps e0 heps he0
  obtain ⟨kPnn, hPnn⟩ := Pifloor_nonneg e0 he0
  use max kf (max kh (max kb kPnn));
  intro BS hBS R hR0
  set C := (labelFin BS c2 R BS.k0).card
  set SB := Real.exp ((2 * eps + eps) * R) * Real.exp ((numBlocks BS : ℝ) * (2 * eps + Real.log (1 / (1 - Real.exp (-eps)))) );
  refine' le_trans ( Finset.sum_le_sum fun H hH => Finset.sum_le_sum fun B hB => _ ) _;
  use fun H B => C * SB * (∏ j ∈ H, Real.exp (eps * Rw c2 j)) * (∏ j ∈ B, Real.exp (eps * Pifloor BS e0 j));
  · refine' le_trans ( hrhs_inner BS c2 R eps H B heps hR0 _ ) _;
    · intro v hv ℓ hℓ;
      apply hfib;
      · exact le_trans hkf ( pow_le_pow_right₀ ( by norm_num ) ( le_trans ( le_max_left _ _ ) hBS ) );
      · exact fun k hk hkH => Finset.mem_filter.mp hv |>.2.2 k hk hkH;
    · rw [ admLabels_card ];
      convert mul_le_mul_of_nonneg_right ( label_product_le BS c2 e0 eps R H B heps.le _ _ _ ) ( show 0 ≤ SB by positivity ) using 1;
      · norm_cast;
      · ring!;
      · exact fun _ _ => div_nonneg ( mul_nonneg hc2.le ( pow_nonneg zero_le_two _ ) ) ( pow_nonneg ( Real.log_nonneg ( one_le_pow₀ ( by norm_num ) ) ) _ );
      · simp +zetaDelta at *;
        exact fun j hj => hPnn BS j ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_powerset.mp ( Finset.mem_filter.mp hB |>.1 ) hj ) ] ) ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_powerset.mp ( Finset.mem_filter.mp hB |>.1 ) hj ) ] ) ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_powerset.mp ( Finset.mem_filter.mp hB |>.1 ) hj ) ] );
      · exact hchg BS ( by linarith [ Nat.le_max_left kf ( Max.max kh ( Max.max kb kPnn ) ), Nat.le_max_right kf ( Max.max kh ( Max.max kb kPnn ) ), Nat.le_max_left kh ( Max.max kb kPnn ), Nat.le_max_right kh ( Max.max kb kPnn ), Nat.le_max_left kb kPnn, Nat.le_max_right kb kPnn ] ) R H B;
  · simp +decide only [mul_assoc, mul_comm, mul_left_comm];
    simp +decide only [← mul_assoc, ← sum_mul];
    simp +decide only [← mul_sum];
    refine' le_trans ( mul_le_mul_of_nonneg_left ( chargeH_le eps c2 R heps hc2 BS ) ( by positivity ) ) _;
    refine' le_trans ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_left ( hchB BS ( by linarith [ Nat.le_max_right kf ( Max.max kh ( Max.max kb kPnn ) ), Nat.le_max_left kh ( Max.max kb kPnn ), Nat.le_max_right kh ( Max.max kb kPnn ), Nat.le_max_left kb kPnn, Nat.le_max_right kb kPnn ] ) R ) ( by positivity ) ) ( by positivity ) ) _ ; ring_nf ; norm_num

/-
**N5 `hrhs` assembly.**  The four-fold fiber
    sum is bounded by `exp(A·numBlocks)·exp(8εR)·(1+√R/σctrl)`.
    (Now fully proved; the cold dominance is supplied via `hdomB`.)

    This statement is TRUE (it is the level-set count of G5), but its proof is
    the genuine remaining obstruction.  The hot/boundary blocks and all
    non-initial cold segments assemble cleanly from `hrhs_inner`,
    `admLabels_card`, `label_product_le`, `sum_subset_charge_le`,
    `fiber_card_exp_bound`, and `sigmaCtrl_le_sigmaP_k0`; but the INITIAL
    segment defeats the per-fiber route: for large `R` the initial label window
    `L0 = ⌈7√R/σ_{k0}⌉` exceeds the `cold_factor` size threshold `N_k·2^k/16`,
    so neither `fiber_card_exp_bound`'s `hlabsize` nor the per-fiber bound it
    yields hold for first-segment cold blocks.  The `√R/σctrl` target factor
    must instead be charged collectively against the first segment's energy via
    a segment-level counting lemma that is not part of the frozen core.

    This is now routed through the label-uniform `fiber_card_exp_bound'`
    (note 45): `hrhs_inner` applies for every `ℓ`, and the `√R/σctrl` factor is
    the first-segment window `L0` via `admLabels_card`/`sigmaCtrl_le_sigmaP_k0`.
-/

lemma hrhs_final (eps : ℝ) (heps : 0 < eps) (heps1 : eps < 1)
    (c2 e0 X0 : ℝ) (hc2 : 0 < c2) (he0 : 0 < e0) (hX0 : 0 < X0)
    (hdom : ∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
        BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k → ¬ isHot BS c2 a k →
        SBEEForcing.IsDominant (2 ^ k) (BS.P k) (restrict BS a k) (1/4))
    (hdomB : ColdDominance c2) :
    ∃ (k0min : ℕ) (A : ℝ), 0 < A ∧
      ∀ (BS : BlockSystem), k0min ≤ BS.k0 → admissibleGlobalRange BS →
      X0 ≤ (2:ℝ) ^ BS.k0 → ∀ R : ℝ, 1 ≤ R →
        (∑ H ∈ admH BS c2 R, ∑ B ∈ admB BS e0 R, ∑ v ∈ admShells BS c2 R H,
          ∑ ℓ ∈ admLabels BS c2 R H B, (fiber BS H B v ℓ).card : ℝ) ≤
          Real.exp (A * (numBlocks BS : ℝ)) *
            Real.exp (8 * eps * R) * (1 + Real.sqrt R / sigmaCtrl BS) := by
  obtain ⟨kc, hc⟩ := hrhs_charge_bound eps c2 e0 heps heps1 hc2 he0 hdomB
  obtain ⟨csig, hcsig0, hsig⟩ := sigmaCtrl_le_sigmaP_k0
  set A0 := 2 * eps + Real.log (1 / (1 - Real.exp (-eps))) + 2
  set A := A0 + |Real.log (3 + 14 * csig)| + 2
  set k0min := max kc 2
  use k0min, A;
  refine' ⟨ _, _ ⟩;
  · exact add_pos_of_pos_of_nonneg ( add_pos_of_pos_of_nonneg ( add_pos_of_pos_of_nonneg ( by positivity ) ( Real.log_nonneg ( by rw [ le_div_iff₀ ] <;> nlinarith [ Real.exp_pos ( -eps ), Real.exp_lt_one_iff.mpr ( show -eps < 0 by linarith ) ] ) ) ) zero_le_two ) ( abs_nonneg _ ) |> add_pos_of_pos_of_nonneg <| by positivity;
  · intro BS hBS hk0 hX0 R hR
    have h_sigmaCtrl_pos : 0 < sigmaCtrl BS := by
      exact sigmaCtrl_pos_of_k0 BS ( le_trans ( le_max_right _ _ ) hBS )
    have h_sigmaP_pos : 0 < sigmaP (BS.P BS.k0) := by
      contrapose! h_sigmaCtrl_pos;
      exact le_trans ( hsig BS ( le_trans ( le_max_right _ _ ) hBS ) ) ( mul_nonpos_of_nonneg_of_nonpos ( by positivity ) h_sigmaCtrl_pos )
    have h_nb : (BS.k0 : ℝ) ≤ numBlocks BS := by
      exact_mod_cast Nat.le_sub_of_add_le ( by linarith [ hk0.1, hk0.2 ] )
    have h_nb_ge_1 : 1 ≤ numBlocks BS := by
      exact Nat.one_le_iff_ne_zero.mpr ( by rw [ numBlocks ] ; exact Nat.sub_ne_zero_of_lt ( by linarith [ hk0.1 ] ) );
    refine' le_trans ( hc BS ( le_trans ( le_max_left _ _ ) hBS ) R ( by positivity ) ) _;
    refine' le_trans ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ( labelFin_k0_card_le BS c2 R ( by positivity ) ) _ ) _ ) _ ) _;
    · positivity;
    · positivity;
    · positivity;
    · -- Apply the bounds on the exponential terms and the logarithmic terms.
      have h_exp_bound : (3 + 14 * Real.sqrt R / sigmaP (BS.P BS.k0)) ≤ (3 + 14 * csig * BS.k0) * (1 + Real.sqrt R / sigmaCtrl BS) := by
        have h_exp_bound : 14 * Real.sqrt R / sigmaP (BS.P BS.k0) ≤ 14 * csig * BS.k0 * Real.sqrt R / sigmaCtrl BS := by
          field_simp;
          grind +locals;
        ring_nf at *;
        nlinarith [ show 0 ≤ Real.sqrt R * ( sigmaCtrl BS ) ⁻¹ by positivity, show 0 ≤ csig * BS.k0 by positivity ];
      have h_exp_bound : (3 + 14 * csig * BS.k0) ≤ Real.exp (|Real.log (3 + 14 * csig)|) * Real.exp (numBlocks BS) := by
        have h_exp_bound : 3 + 14 * csig * BS.k0 ≤ (3 + 14 * csig) * BS.k0 := by
          nlinarith [ show ( BS.k0 : ℝ ) ≥ 2 by norm_cast; exact le_trans ( le_max_right _ _ ) hBS ];
        refine le_trans h_exp_bound ?_;
        gcongr;
        · rw [ abs_of_nonneg ( Real.log_nonneg ( by linarith ) ), Real.exp_log ( by linarith ) ];
        · exact le_trans h_nb ( by linarith [ Real.add_one_le_exp ( numBlocks BS : ℝ ) ] );
      refine' le_trans ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ‹_› _ ) _ ) _ ) _;
      · positivity;
      · positivity;
      · positivity;
      · refine' le_trans ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right ( mul_le_mul_of_nonneg_right h_exp_bound _ ) _ ) _ ) _ ) _;
        · positivity;
        · positivity;
        · positivity;
        · positivity;
        · norm_num [ ← Real.exp_add ] ; ring_nf;
          norm_num [ A, A0 ] ; ring_nf;
          norm_num [ mul_assoc, ← Real.exp_add, ← Real.exp_nat_mul ] ; ring_nf;
          refine' add_le_add _ _;
          · rw [ mul_assoc, mul_assoc, mul_assoc, mul_comm ];
            rw [ mul_assoc, mul_assoc, ← Real.exp_add ] ; ring_nf;
            exact mul_le_mul_of_nonneg_left ( Real.exp_le_exp.mpr <| by nlinarith [ show ( numBlocks BS : ℝ ) ≥ 1 by norm_cast, abs_nonneg ( Real.log ( 3 + csig * 14 ) ) ] ) <| by positivity;
          · exact Real.exp_le_exp.mpr ( by nlinarith [ show ( numBlocks BS : ℝ ) ≥ 1 by norm_cast, show ( |Real.log ( 3 + csig * 14 )| : ℝ ) ≥ 0 by positivity, show ( eps : ℝ ) ≥ 0 by positivity, show ( R : ℝ ) ≥ 1 by norm_cast ] )

/-- **G5 — global level-set theorem (final assembly).**  Identical statement to
    `GlobalControl.global_levelset`; kept in this leaf to avoid the cyclic
    import.  Assembles `cold_master`, `hadmL_final`, and `hrhs_final` through
    `global_levelset_route`. -/

lemma exists_pow_ge_affine (D : ℝ) :
    ∃ N : ℕ, ∀ k : ℕ, N ≤ k → D * ((k : ℝ) + 1) ≤ (2 : ℝ) ^ k := by
  -- The sequence $\frac{k+1}{2^k}$ tends to $0$ as $k$ tends to infinity.
  have h_seq_zero : Filter.Tendsto (fun k : ℕ => (k + 1 : ℝ) / 2 ^ k) Filter.atTop (nhds 0) := by
    refine' squeeze_zero_norm' _ tendsto_inv_atTop_nhds_zero_nat;
    norm_num;
    exact ⟨ 8, fun n hn => by rw [ inv_eq_one_div, div_le_div_iff₀ ] <;> norm_cast <;> induction hn <;> norm_num [ Nat.pow_succ ] at * ; nlinarith ⟩;
  rcases Metric.tendsto_atTop.mp h_seq_zero ( 1 / ( Max.max D 1 ) ) ( by positivity ) with ⟨ N, hN ⟩;
  simp +zetaDelta at *;
  exact ⟨ N, fun n hn => by have := hN n hn; rw [ div_lt_iff₀ ( by positivity ) ] at this; rw [ abs_of_nonneg ( by positivity ) ] at this; nlinarith [ le_max_left D 1, le_max_right D 1, inv_mul_cancel₀ ( show ( max D 1 ) ≠ 0 by positivity ), pow_pos ( zero_lt_two' ℝ ) n ] ⟩

/-
**L2 core (`Pifloor_ge_Rw`).**  For `k` large enough (density past the
exception threshold, exponential-beats-linear), the boundary penalty floor at
block `k` dominates the forcing floor at `k`.  Single-index analytic core.
-/

lemma Pifloor_ge_Rw (c2 e0 : ℝ) (he0 : 0 < e0) :
    ∃ k0min : ℕ, 4 ≤ k0min ∧
      ∀ (BS : BlockSystem), k0min ≤ BS.k0 →
        ∀ k, BS.k0 ≤ k → k < BS.K → Rw c2 k ≤ Pifloor BS e0 k := by
  obtain ⟨Na, hNa⟩ := exists_pow_ge_affine (4 * e0 * Real.log 2)
  obtain ⟨Nb, hNb⟩ := exists_pow_ge_affine (2 * (e0 + 1) * Real.log 2)
  obtain ⟨Nc, hNc⟩ := exists_pow_ge_affine (2 ^ 20 * c2 * Real.log 2);
  refine' ⟨ 4 + Na + Nb + Nc, _, _ ⟩;
  · linarith;
  · intro BS hBS k hk hk'; rw [ Rw, Pifloor ] ;
    -- Apply the density bounds from `hdensity`.
    have h_density_k : (BS.P k).card ≥ (2 ^ k : ℝ) / (2 * (k : ℝ) * Real.log 2) := by
      have := BS.hdensity k ( by linarith ) ( by linarith ) ; simp_all +decide [ mul_assoc, mul_comm, mul_left_comm ] ;
    have h_density_k1 : (BS.P (k + 1)).card ≥ (2 * 2 ^ k : ℝ) / (2 * ((k + 1) : ℝ) * Real.log 2) := by
      have := BS.hdensity ( k + 1 ) ( by linarith ) ( by linarith ) ; norm_num [ Real.log_pow ] at * ; ring_nf at * ; aesop;
    -- Apply the bounds from `hNa`, `hNb`, and `hNc`.
    have h_bounds : (2 ^ k : ℝ) / (4 * (k : ℝ) * Real.log 2) ≤ (BS.P k).card - e0 ∧ (2 ^ k : ℝ) / (2 * ((k + 1) : ℝ) * Real.log 2) ≤ (BS.P (k + 1)).card - e0 - 1 := by
      constructor;
      · rw [ ge_iff_le, div_le_iff₀ ] at * <;> try positivity;
        · nlinarith [ hNa k ( by linarith ), Real.log_pos one_lt_two, show ( k : ℝ ) ≥ 4 by norm_cast; linarith ];
        · exact mul_pos ( mul_pos two_pos ( Nat.cast_pos.mpr ( by linarith ) ) ) ( Real.log_pos one_lt_two );
        · exact mul_pos ( mul_pos ( by norm_num ) ( Nat.cast_pos.mpr ( by linarith ) ) ) ( Real.log_pos ( by norm_num ) );
      · rw [ ge_iff_le, div_le_iff₀ ] at * <;> try positivity;
        · nlinarith [ hNb k ( by linarith ), Real.log_pos one_lt_two ];
        · exact mul_pos ( mul_pos two_pos ( Nat.cast_pos.mpr ( by linarith ) ) ) ( Real.log_pos one_lt_two );
    refine' le_trans _ ( div_le_div_of_nonneg_right ( mul_le_mul h_bounds.2 ( pow_le_pow_left₀ _ h_bounds.1 3 ) _ _ ) _ );
    · rw [ div_mul_eq_mul_div, div_div, div_le_div_iff₀ ] <;> norm_num [ Real.log_pow ] <;> ring_nf <;> norm_num [ Real.log_pos ];
      · field_simp;
        rw [ mul_div_cancel_left₀ _ ( by norm_cast; linarith ) ] ; ring_nf at *;
        convert mul_le_mul_of_nonneg_right ( hNc k ( by linarith ) ) ( pow_nonneg ( by positivity : ( 0 : ℝ ) ≤ 2 ) ( k * 3 ) ) using 1 <;> ring;
      · exact pow_pos ( Nat.cast_pos.mpr ( by linarith ) ) _;
      · exact add_pos_of_nonneg_of_pos ( mul_nonneg ( mul_nonneg ( Nat.cast_nonneg _ ) ( Real.log_nonneg ( by norm_num ) ) ) zero_le_two ) ( mul_pos ( Real.log_pos ( by norm_num ) ) zero_lt_two );
    · positivity;
    · positivity;
    · exact le_trans ( by positivity ) h_bounds.2;
    · positivity

/-- **L2 (`Rw_le_Pifloor`).**  For `k0` large enough (density past the
exception threshold, power-beats-poly-log), the forcing floor at `k0` is below
the boundary penalty floor at any block `k0 ≤ k < K`. -/

lemma ctrlPairs_prod_lower (BS : BlockSystem) (hk0 : 2 ≤ BS.k0) {pq : ℕ × ℕ}
    (h : pq ∈ ctrlPairs BS) :
    (2 : ℝ) ^ (2 * BS.k0) < (pq.1 : ℝ) * (pq.2 : ℝ) := by
  -- Both endpoints are prime and ≥ 2^k0, hence strictly > 2^k0.
  have h1 : 2 ^ BS.k0 < pq.1 := by
    obtain ⟨k, hk⟩ : ∃ k, pq.1 ∈ BS.P k ∧ BS.k0 ≤ k ∧ k ≤ BS.K := by
      obtain ⟨k, hk⟩ : ∃ k, pq.1 ∈ BS.P k ∧ k ∈ Finset.Icc BS.k0 BS.K := by
        have h_mem : pq.1 ∈ blockSupport BS := by
          exact ctrlPairs_mem_blockSupport BS h |>.1
        unfold blockSupport at h_mem; aesop;
      aesop;
    have := BS.hwindow k pq.1 hk.1;
    by_cases h_eq : pq.1 = 2 ^ BS.k0;
    · have := BS.hprime k pq.1 hk.1; simp_all +decide [ Nat.prime_iff ] ;
    · exact lt_of_le_of_ne ( Nat.le_trans ( pow_le_pow_right₀ ( by decide ) hk.2.1 ) this.1 ) ( Ne.symm h_eq )
  have h2 : 2 ^ BS.k0 < pq.2 := by
    cases' Finset.mem_union.mp ( show pq ∈ ( Finset.biUnion ( Finset.Icc BS.k0 BS.K ) ( internalPairs BS ) ) ∪ ( Finset.biUnion ( Finset.Ico BS.k0 BS.K ) ( bipartitePairs BS ) ) from h );
    · simp_all +decide [ Finset.mem_biUnion, internalPairs ];
      grind;
    · simp_all +decide [ bipartitePairs ];
      obtain ⟨ k, hk, hk₁, hk₂ ⟩ := ‹_›; have := BS.hwindow ( k + 1 ) pq.2 hk₂; simp_all +decide [ pow_succ' ] ;
      linarith [ pow_le_pow_right₀ ( by decide : 1 ≤ 2 ) hk.1 ];
  norm_cast; rw [ pow_mul' ] ; nlinarith [ pow_pos ( zero_lt_two' ℕ ) BS.k0 ] ;

/-! ## L5 — the diagonal energy identity -/

/-
**L5 (`diagonal_Qctrl`).**  If `a` is globally diagonal with label `m` and
`2·|m| < p·q` for every control pair, then `Qctrl a = m²·σ²`.
-/

lemma diagonal_Qctrl (BS : BlockSystem) (a : GlobalAssignment BS) (m : ℤ)
    (hdiag : ∀ p : {p : ℕ // p ∈ blockSupport BS}, (a p : ZMod p.1) = (m : ZMod p.1))
    (hsmall : ∀ pq ∈ ctrlPairs BS, 2 * |m| < (pq.1 : ℤ) * (pq.2 : ℤ)) :
    Qctrl BS a = (m : ℝ) ^ 2 * (sigmaCtrl BS) ^ 2 := by
  convert Finset.sum_congr rfl fun pq hpq => ?_ using 1;
  rotate_left;
  use fun pq => ( m : ℝ ) ^ 2 / ( pq.1 * pq.2 ) ^ 2;
  · rw [ Hglob, crtRepr_eq_label_of_small pq.1 pq.2 ( blockSupport_prime BS ( ctrlPairs_mem_blockSupport BS hpq |>.1 ) ) ( blockSupport_prime BS ( ctrlPairs_mem_blockSupport BS hpq |>.2 ) ) ( ctrlPairs_ne BS hpq ) m ];
    · ring;
    · exact if_pos ( ctrlPairs_mem_blockSupport BS hpq |>.1 ) |> fun h => h.trans ( hdiag ⟨ pq.1, ctrlPairs_mem_blockSupport BS hpq |>.1 ⟩ );
    · convert hdiag ⟨ pq.2, ctrlPairs_mem_blockSupport BS hpq |>.2 ⟩ using 1;
      exact dif_pos ( ctrlPairs_mem_blockSupport BS hpq |>.2 );
    · exact hsmall pq hpq;
  · unfold sigmaCtrl; rw [ Real.sq_sqrt <| Finset.sum_nonneg fun _ _ => by positivity ] ; simp +decide [ div_eq_mul_inv, mul_comm, Finset.mul_sum _ _ _ ] ;

/-! ## L3 — Case D collapse: the substantive `cold_no_exceptions` step -/

/- **Bundled cold constants + the substantive `cold_no_exceptions` step.**

Produces the cold constants `c2,e0,X0` (a refinement of those produced by
`boundary_penalty_per_k`, with `c2` shrunk to be explicitly small), together with:
* the per-cold-block facts (small exception set, sharp label bound, conformity);
* the boundary penalty floor (`Pifloor ≤ Xen`);
* **`cold_no_exceptions`**: in the no-hot regime every cold block has an empty
  exception set.

The first two components are derived from `boundary_penalty_per_k` by
monotonicity in `c2`.  The third is the genuinely new G6 input (note 34 §G6),
proved in `cold_no_exceptions_core`. -/
/-- Monotonicity of the forcing floor in its constant: a smaller `c2` gives a
smaller `Rw`. -/

lemma cold_no_exceptions_core (c2 e0 : ℝ) (hc2 : 0 < c2) (hc2small : c2 ≤ 1 / 2 ^ 21)
    (he0 : 0 < e0) :
    ∃ X0 : ℝ, 0 < X0 ∧ ∀ (BS : BlockSystem) (a : GlobalAssignment BS) (k : ℕ),
      BS.k0 ≤ k → k ≤ BS.K → X0 ≤ (2:ℝ) ^ k → ¬ isHot BS c2 a k →
      ((excSet BS a k).card : ℝ) ≤ e0 →
      |(coldLabel BS a k : ℝ)| ≤ ((BS.P k).card : ℝ) * ((2:ℝ) ^ k) / 64 →
      excSet BS a k = ∅ := by
  obtain ⟨ X0r, hX0r_pos, hX0r ⟩ := GlobalControl.Rw_large 1 c2 hc2 ; obtain ⟨ X0d, hX0d_pos, hX0d ⟩ := SBEEForcing.exists_X0_const_logbnd ( 8 * e0 + 64 ) ; use max 16 ( max X0r X0d ) ; norm_num at *;
  intro BS a k hk0 hkK hk16 hkX0r hkX0d hnot_hot hexc hlabel
  have hblock : 4 ≤ k := by
    exact le_of_not_gt fun h => by interval_cases k <;> norm_num at hk16;
  have hX : 16 ≤ 2 ^ k := by
    exact_mod_cast hk16
  have hXr : 1 ≤ k := by
    linarith
  have hXd : X0d ≤ (2 ^ k : ℝ) := by
    exact_mod_cast hkX0d
  have hX0r' : X0r ≤ (2 ^ k : ℝ) := by
    exact_mod_cast hkX0r
  have hR : 1 ≤ Rw c2 k := by
    exact hX0r k hXr hX0r'
  have hclass : (1 - 1 / 4 : ℝ) * (BS.P k).card ≤ (classCount BS a k (coldLabel BS a k) : ℝ) := by
    have hclass : (classCount BS a k (coldLabel BS a k) : ℝ) = (BS.P k).card - (excSet BS a k).card := by
      rw [ ← conform_card_eq BS a k ( Finset.mem_Icc.mpr ⟨ hk0, hkK ⟩ ), Finset.card_sdiff ];
      rw [ Finset.inter_eq_left.mpr ( excSet_subset BS a k ), Nat.cast_sub ( Finset.card_le_card ( excSet_subset BS a k ) ) ]
    generalize_proofs at *;
    have := BS.hdensity k hk0 hkK; norm_num at *; (
    have := hX0d ( 2 ^ k ) ( by simpa using hXd ) ; norm_num at * ; ( rw [ div_le_iff₀ ] at * <;> try positivity ) ;
    nlinarith [ show ( 0 : ℝ ) < k * Real.log 2 by positivity ]);
  generalize_proofs at *;
  have hN : (BS.P k).card ≥ (2 ^ k : ℝ) / (2 * Real.log (2 ^ k)) := by
    exact BS.hdensity k hk0 hkK
  have hN32 : 32 ≤ (BS.P k).card := by
    have := hX0d ( 2 ^ k ) ( by exact_mod_cast hXd ) ; norm_num at *;
    rw [ div_le_iff₀ ( by positivity ) ] at hN;
    exact_mod_cast ( by nlinarith [ show ( 0 :ℝ ) < k * Real.log 2 by positivity ] : ( 32 :ℝ ) ≤ # ( BS.P k ) )
  have hNpos : 0 < (BS.P k).card := by
    linarith
  have hN_ge_4e0 : 4 * e0 ≤ (BS.P k).card := by
    have := hX0d ( 2 ^ k ) ( by simpa using hXd ) ; norm_num at *;
    rw [ div_le_iff₀ ( by positivity ) ] at hN ; nlinarith [ Real.log_pos one_lt_two, show ( k : ℝ ) ≥ 4 by norm_cast, show ( 2 : ℝ ) ^ k > 0 by positivity ] ;
  generalize_proofs at *;
  have hmsmall : |(coldLabel BS a k : ℝ)| ≤ (BS.P k).card * (2 ^ k : ℝ) / 16 := by
    exact hlabel.trans ( by gcongr ; norm_num )
  generalize_proofs at *;
  have hcount : (excSet BS a k).card ≤ 2 ^ 15 * Rw c2 k * (2 ^ k : ℝ) ^ 2 / ((1 - 1 / 4) * (BS.P k).card ^ 3) := by
    have hQ : QP (BS.P k) (restrict BS a k) ≤ Rw c2 k := by
      exact le_of_not_ge fun h => hnot_hot <| by unfold isHot; exact h;
    generalize_proofs at *;
    have := SBEEForcing.exception_count_bound ( 2 ^ k ) ( by linarith ) ( BS.P k ) ( by
      exact fun p hp => ⟨ BS.hprime k p hp, by linarith [ BS.hwindow k p hp ], by linarith [ BS.hwindow k p hp, show 2 ^ ( k + 1 ) = 2 * 2 ^ k by ring ] ⟩ ) ( by linarith ) ( 1 / 4 ) ( by linarith ) ( by linarith ) ( restrict BS a k ) ( coldLabel BS a k ) ( Rw c2 k ) ( by linarith ) ( by
      exact hQ ) ( by
      exact_mod_cast hmsmall ) ( by
      convert hclass using 1 )
    generalize_proofs at *;
    convert this using 1 ; norm_num [ excSet_card_eq ];
    · convert excSet_card_eq BS a k ( Finset.mem_Icc.mpr ⟨ hk0, hkK ⟩ ) using 1;
    · norm_cast
  generalize_proofs at *;
  -- Substitute the bounds into the inequality.
  have h_subst : (excSet BS a k).card ≤ 2 ^ 15 * (c2 * (2 ^ k : ℝ) / (Real.log (2 ^ k)) ^ 3) * (2 ^ k : ℝ) ^ 2 / ((1 - 1 / 4) * ((2 ^ k : ℝ) / (2 * Real.log (2 ^ k))) ^ 3) := by
    refine le_trans hcount ?_;
    gcongr;
    · exact mul_pos ( by norm_num ) ( pow_pos ( div_pos ( by positivity ) ( mul_pos zero_lt_two ( Real.log_pos ( by norm_cast; linarith ) ) ) ) _ );
    · exact le_rfl;
    · exact div_nonneg ( by positivity ) ( mul_nonneg zero_le_two ( Real.log_nonneg ( by norm_cast; linarith ) ) )
  generalize_proofs at *;
  -- Simplify the expression to show that it is less than 1.
  have h_simplified : (excSet BS a k).card ≤ 2 ^ 20 * c2 / 3 := by
    convert h_subst using 1 ; ring_nf ; norm_num [ Real.log_pow ] ; ring_nf ; norm_num [ show ( 2 : ℝ ) ^ k ≠ 0 by positivity, show ( Real.log 2 : ℝ ) ≠ 0 by positivity ] ;
    norm_num [ show k ≠ 0 by linarith, show ( 2 : ℝ ) ^ ( k * 3 ) ≠ 0 by positivity ];
    norm_num [ mul_assoc, ← mul_pow ]
  generalize_proofs at *;
  exact Finset.card_eq_zero.mp ( Nat.eq_zero_of_le_zero ( Nat.le_of_lt_succ ( by rw [ ← @Nat.cast_lt ℝ ] ; push_cast; linarith ) ) )

theorem g6_localization :
    ∃ (k0loc : ℕ) (c2 e0 : ℝ), 0 < c2 ∧ 0 < e0 ∧
      ∀ (BS : BlockSystem), k0loc ≤ BS.k0 → admissibleGlobalRange BS →
      ∀ (C : ℝ), 1 ≤ C →
      ∀ a : GlobalAssignment BS, a ∉ mainArc BS C →
        globalControlFloor BS c2 e0 ≤ Qctrl BS a ∨ diagSector BS C a := by
  obtain ⟨c2, e0, X0, hc2, he0, hX0, hcf, hbd, hnoexc⟩ := GlobalControl.cold_no_exceptions;
  obtain ⟨kRwPi, hkRwPi4, hRwPi⟩ := GlobalControl.Rw_le_Pifloor c2 e0 hc2 he0;
  obtain ⟨N, hN⟩ : ∃ N : ℕ, X0 < 2 ^ N := by
    exact pow_unbounded_of_one_lt X0 one_lt_two;
  refine' ⟨ Max.max ( Max.max 4 kRwPi ) N, c2, e0, hc2, he0, fun BS hk0 hadm C hC a ha => _ ⟩;
  by_cases hH : (hotSet BS c2 a).Nonempty;
  · obtain ⟨ k, hk ⟩ := hH;
    refine' Or.inl ( le_trans _ ( blockEnergy_le_Qctrl BS a k _ ) );
    · refine' le_trans ( min_le_left _ _ ) _;
      refine' le_trans _ ( Finset.mem_filter.mp hk |>.2 );
      exact Rw_mono c2 hc2 ( by linarith [ Finset.mem_Icc.mp ( Finset.mem_filter.mp hk |>.1 ), le_max_left ( max 4 kRwPi ) N, le_max_right ( max 4 kRwPi ) N, le_max_left 4 kRwPi, le_max_right 4 kRwPi ] ) ( by linarith [ Finset.mem_Icc.mp ( Finset.mem_filter.mp hk |>.1 ), le_max_left ( max 4 kRwPi ) N, le_max_right ( max 4 kRwPi ) N, le_max_left 4 kRwPi, le_max_right 4 kRwPi ] );
    · exact Finset.mem_filter.mp hk |>.1;
  · by_cases hB : (boundarySet BS c2 a).Nonempty;
    · obtain ⟨ k, hk ⟩ := hB;
      refine' Or.inl ( le_trans _ ( le_trans ( hRwPi BS ( by linarith [ le_max_left ( max 4 kRwPi ) N, le_max_right ( max 4 kRwPi ) N, le_max_left 4 kRwPi, le_max_right 4 kRwPi ] ) hadm k ( by
        exact Finset.mem_Ico.mp ( Finset.mem_filter.mp hk |>.1 ) |>.1 ) ( by
        exact Finset.mem_Ico.mp ( Finset.mem_filter.mp hk |>.1 ) |>.2 ) ) ( le_trans ( hbd BS a k ( by
        exact Finset.mem_Ico.mp ( Finset.mem_filter.mp hk |>.1 ) |>.1 ) ( by
        exact Finset.mem_Ico.mp ( Finset.mem_filter.mp hk |>.1 ) |>.2 ) ( by
        exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_filter.mp hk |>.1 ), le_max_right ( max 4 kRwPi ) N, le_max_right 4 kRwPi, le_max_left ( max 4 kRwPi ) N, le_max_left 4 kRwPi, le_max_right ( max 4 kRwPi ) N, le_max_right 4 kRwPi, hk0 ] ) ) ) hk ) ( Xen_le_Qctrl BS a k ( by
        exact Finset.mem_filter.mp hk |>.1 ) ) ) ) );
      exact min_le_left _ _;
    · refine Or.inr ⟨ coldLabel BS a BS.k0, ?_, ?_, ?_ ⟩;
      · intro p
        obtain ⟨k, hk0k, hkK, hpk⟩ : ∃ k, BS.k0 ≤ k ∧ k ≤ BS.K ∧ p.val ∈ BS.P k := by
          exact Exists.elim ( Finset.mem_biUnion.mp p.2 ) fun k hk => ⟨ k, by aesop ⟩;
        have hcold : coldLabel BS a k = coldLabel BS a BS.k0 := by
          convert coldLabel_eq_segStart BS c2 a k hk0k hkK _ using 1;
          · rw [ show segStart BS ( hotSet BS c2 a ) ( boundarySet BS c2 a ) k = BS.k0 from ?_ ];
            rw [ show hotSet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hH, show boundarySet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hB ] ; exact segStart_empty BS k;
          · exact fun h => hH ⟨ k, h ⟩;
        have := hcf BS a k hk0k hkK ( by linarith [ pow_le_pow_right₀ ( by norm_num : ( 1 : ℝ ) ≤ 2 ) ( show k ≥ N by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) ] ) ( by
                                                                                                          exact fun h => hH ⟨ k, Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ hk0k, hkK ⟩, h ⟩ ⟩ );
        convert this.2.2 p.val ( Finset.mem_sdiff.mpr ⟨ hpk, ?_ ⟩ ) using 1;
        · unfold toPlain; aesop;
        · rw [ hcold ];
        · exact fun h => by have := hnoexc BS a k hk0k hkK ( by
            exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) ) ) ( by
            exact fun h => hH ⟨ k, Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ hk0k, hkK ⟩, h ⟩ ⟩ ) ; exact Finset.notMem_empty _ ( this ▸ h ) ;
      · contrapose! ha;
        refine' ⟨ coldLabel BS a BS.k0, ha, _ ⟩;
        intro p
        obtain ⟨k, hk0k, hkK, hpk⟩ : ∃ k, BS.k0 ≤ k ∧ k ≤ BS.K ∧ p.val ∈ BS.P k := by
          have := Finset.mem_biUnion.mp p.2; aesop;
        have hck : ¬ isHot BS c2 a k := by
          exact fun h => hH ⟨ k, Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ hk0k, hkK ⟩, h ⟩ ⟩;
        have hck : toPlain BS a p = coldLabel BS a k := by
          apply (hcf BS a k hk0k hkK (by
          exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) )) hck).right.right p (by
          simp [hnoexc BS a k hk0k hkK (by
          exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) )) hck];
          exact hpk);
        have hck : coldLabel BS a k = coldLabel BS a BS.k0 := by
          convert coldLabel_eq_segStart BS c2 a k hk0k hkK _ using 1;
          · rw [ show segStart BS ( hotSet BS c2 a ) ( boundarySet BS c2 a ) k = BS.k0 from ?_ ];
            rw [ show hotSet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hH, show boundarySet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hB ] ; exact segStart_empty BS k;
          · exact fun h => hH ⟨ k, h ⟩;
        unfold toPlain at *; aesop;
      · apply diagonal_Qctrl;
        · intro p
          obtain ⟨k, hk0k, hkK, hpk⟩ : ∃ k, BS.k0 ≤ k ∧ k ≤ BS.K ∧ p.val ∈ BS.P k := by
            exact Exists.elim ( Finset.mem_biUnion.mp p.2 ) fun k hk => ⟨ k, by aesop ⟩;
          have hck : ¬ isHot BS c2 a k := by
            exact fun h => hH ⟨ k, Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ hk0k, hkK ⟩, h ⟩ ⟩;
          have hck : coldLabel BS a k = coldLabel BS a BS.k0 := by
            convert coldLabel_eq_segStart BS c2 a k hk0k hkK _ using 1;
            · rw [ show segStart BS ( hotSet BS c2 a ) ( boundarySet BS c2 a ) k = BS.k0 from ?_ ];
              rw [ show hotSet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hH, show boundarySet BS c2 a = ∅ from Finset.not_nonempty_iff_eq_empty.mp hB ] ; exact segStart_empty BS k;
            · exact fun h => hH ⟨ k, h ⟩;
          have := hcf BS a k hk0k hkK ( by
            exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) ) ) ‹_›;
          convert this.2.2 p.val ( Finset.mem_sdiff.mpr ⟨ hpk, by
            exact fun h => by have := hnoexc BS a k hk0k hkK ( by
              exact le_trans ( le_of_lt hN ) ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) ) ) ‹_›; simp_all +decide [ Finset.ext_iff ] ; ⟩ ) using 1;
          · unfold toPlain; aesop;
          · rw [ hck ];
        · intro pq hpq
          have h_label_bound : |(coldLabel BS a BS.k0 : ℝ)| ≤ (2 : ℝ) ^ (2 * BS.k0) / 64 := by
            have h_label_bound : |(coldLabel BS a BS.k0 : ℝ)| ≤ ((BS.P BS.k0).card : ℝ) * (2 : ℝ) ^ BS.k0 / 64 := by
              apply (hcf BS a BS.k0 (by linarith) (by linarith [BS.hk]) (by
              exact le_trans hN.le ( pow_le_pow_right₀ ( by norm_num ) ( by linarith [ Nat.le_max_right ( max 4 kRwPi ) N ] ) )) (by
              exact fun h => hH ⟨ BS.k0, Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ by linarith, by linarith [ BS.hk ] ⟩, h ⟩ ⟩)).right.left;
            refine le_trans h_label_bound ?_;
            rw [ pow_mul' ];
            rw [ sq ];
            rw [ mul_comm ] ; gcongr;
            exact_mod_cast GlobalControl.block_card_le BS BS.k0;
          have h_prod_bound : (2 : ℝ) ^ (2 * BS.k0) < (pq.1 : ℝ) * (pq.2 : ℝ) := by
            exact_mod_cast ctrlPairs_prod_lower BS ( by linarith [ le_max_left ( max 4 kRwPi ) N, le_max_right ( max 4 kRwPi ) N, le_max_left 4 kRwPi, le_max_right 4 kRwPi ] ) hpq;
          rw [ ← @Int.cast_lt ℝ ] ; push_cast ; linarith [ abs_nonneg ( coldLabel BS a BS.k0 : ℝ ) ]

end GlobalControl

lemma shell_sum_bound {ι : Type*} [Fintype ι] [DecidableEq ι] (c : ι → ℕ → ℝ)
    (alpha beta R : ℝ) (halpha : 0 < alpha) (hbeta : 0 < beta) (hR : 0 ≤ R)
    (hc0 : ∀ k n, 0 ≤ c k n)
    (hcb : ∀ k (n : ℕ), c k n ≤ Real.exp (alpha * (n + 1))) :
    ∑ v ∈ (Fintype.piFinset (fun _ : ι => Finset.range (⌊R⌋₊ + 1))).filter
        (fun v => (∑ k, (v k : ℝ)) ≤ R),
      ∏ k, c k (v k)
    ≤ Real.exp ((alpha + beta) * R) *
      Real.exp ((Fintype.card ι : ℝ) *
        (alpha + Real.log (1 / (1 - Real.exp (-beta))))) := by
  -- For each admissible v (in the filter, so ∑ k, (v k : ℝ) ≤ R), bound the product:
  have h_bound : ∀ v ∈ Fintype.piFinset (fun _ => Finset.range (⌊R⌋₊ + 1)), (∑ k, (v k : ℝ)) ≤ R → (∏ k, c k (v k)) ≤ Real.exp (alpha * Fintype.card ι) * Real.exp ((alpha + beta) * R) * (∏ k, Real.exp (-beta * (v k : ℝ))) := by
    -- Using the bounds on $c_k(n)$ and the fact that $\sum_{k} v_k \leq R$, we can show that the product of $c_k(v_k)$ is bounded by the exponential term.
    intros v hv hvR
    have h_prod_bound : (∏ k, c k (v k)) ≤ Real.exp (alpha * (∑ k, (v k + 1))) := by
      exact le_trans ( Finset.prod_le_prod ( fun _ _ => hc0 _ _ ) fun _ _ => hcb _ _ ) ( by simp +decide [ ← Real.exp_sum, mul_add, Finset.mul_sum _ _ _ ] );
    simp_all +decide [ mul_add, ← Real.exp_add, Finset.sum_add_distrib ];
    rw [ ← Real.exp_sum, ← Real.exp_add ];
    exact h_prod_bound.trans ( Real.exp_le_exp.mpr <| by nlinarith [ show ( ∑ k : ι, ( v k : ℝ ) ) ≥ 0 by exact Finset.sum_nonneg fun _ _ => Nat.cast_nonneg _, show ( ∑ k : ι, - ( beta * ( v k : ℝ ) ) ) = - ( beta * ∑ k : ι, ( v k : ℝ ) ) by rw [ Finset.mul_sum _ _ _ ] ; rw [ Finset.sum_neg_distrib ] ] );
  -- Therefore, the filtered sum ≤ sum over ALL v ∈ piFinset of [exp(alpha*card)*exp((alpha+beta)*R)*∏ k, exp(-beta*(v k))], by extending the filter to the whole piFinset (all terms nonnegative).
  have h_sum_bound : (∑ v ∈ Fintype.piFinset (fun _ => Finset.range (⌊R⌋₊ + 1)) |>.filter (fun v => ∑ k, (v k : ℝ) ≤ R), (∏ k, c k (v k))) ≤ Real.exp (alpha * Fintype.card ι) * Real.exp ((alpha + beta) * R) * (∏ k : ι, (∑ n ∈ Finset.range (⌊R⌋₊ + 1), Real.exp (-beta * (n : ℝ)))) := by
    refine' le_trans ( Finset.sum_le_sum fun v hv => h_bound v ( Finset.mem_filter.mp hv |>.1 ) ( Finset.mem_filter.mp hv |>.2 ) ) _;
    refine' le_trans ( Finset.sum_le_sum_of_subset_of_nonneg ( Finset.filter_subset _ _ ) fun _ _ _ => mul_nonneg ( mul_nonneg ( Real.exp_nonneg _ ) ( Real.exp_nonneg _ ) ) ( Finset.prod_nonneg fun _ _ => Real.exp_nonneg _ ) ) _;
    rw [ ← Finset.mul_sum _ _ _, Finset.prod_sum ];
    refine' le_of_eq _;
    refine' congr_arg _ ( Finset.sum_bij ( fun v hv => fun k _ => v k ) _ _ _ _ ) <;> simp +decide;
    · simp +contextual [ funext_iff ];
    · exact fun b hb => ⟨ fun k => b k ( Finset.mem_univ k ), hb, rfl ⟩;
  -- Each inner geometric sum: ∑ n ∈ range N, exp(-beta*n) = ∑ n ∈ range N, (exp(-beta))^n ≤ 1/(1-exp(-beta)) since 0 ≤ exp(-beta) < 1.
  have h_geo_sum : ∀ N : ℕ, (∑ n ∈ Finset.range N, Real.exp (-beta * (n : ℝ))) ≤ 1 / (1 - Real.exp (-beta)) := by
    intro N
    have h_geo_sum : (∑ n ∈ Finset.range N, Real.exp (-beta * (n : ℝ))) = (∑ n ∈ Finset.range N, (Real.exp (-beta)) ^ n) := by
      exact Finset.sum_congr rfl fun _ _ => by rw [ ← Real.exp_nat_mul ] ; ring;
    rw [ h_geo_sum, one_div, ← tsum_geometric_of_lt_one ( by positivity ) ( by norm_num; positivity ) ] ; exact Summable.sum_le_tsum ( Finset.range N ) ( fun _ _ => by positivity ) ( by exact summable_geometric_of_lt_one ( by positivity ) ( by norm_num; positivity ) ) ;
  convert h_sum_bound.trans ( mul_le_mul_of_nonneg_left ( Finset.prod_le_prod ( fun _ _ => Finset.sum_nonneg fun _ _ => Real.exp_nonneg _ ) fun _ _ => h_geo_sum _ ) ( by positivity ) ) using 1 ; ring;
  simp +decide [ mul_assoc, ← Real.exp_add, ← Real.exp_nat_mul ];
  rw [ ← Real.rpow_natCast, Real.rpow_def_of_pos ( sub_pos.mpr <| Real.exp_lt_one_iff.mpr <| neg_lt_zero.mpr hbeta ) ] ; ring;
  rw [ ← Real.exp_neg, ← Real.exp_add ] ; ring

/-- **Segment label constancy** (note 34 G5 step 4 / note 37 §3.2 "segment
construction").  If across every index `k` of a connected run the edge predicate
`P k` forces `label k = label (k+1)`, then the label is constant throughout the
run: any two endpoints `i ≤ j` whose intermediate edges all satisfy `P` carry
equal labels.  This is the combinatorial heart of "labels are constant on each
cold segment". -/

theorem sameRefProjective_symm
    {x0 x1 x2 x3 x4 z0 z1 z2 z3 z4 : ℤ}
    (h : SameRefProjective x0 x1 x2 x3 x4 z0 z1 z2 z3 z4) :
    SameRefProjective z0 z1 z2 z3 z4 x0 x1 x2 x3 x4 := by
  cases h;
  exact ⟨ by linarith, by linarith, by linarith, by linarith ⟩

def E (D : R2ConcreteData T b) : Finset ℕ :=
  r2Edges D.BS D.Q D.R D.S

/-- The block-support period used by the R2 construction skeleton. -/

def L (D : R2ConcreteData T b) : ℕ :=
  primeSupportPeriod b (blockSupport D.BS)

/-- Reciprocal load of an edge set. -/

def recipLoad (E : Finset ℕ) : ℝ :=
  ∑ e ∈ E, (1 : ℝ) / (e : ℝ)

/-- The already-fixed part of the R2 load, before adding the residual mass batch. -/

def CoversPrimeDivisors (R : Finset ℕ) (b : ℕ) : Prop :=
  ∀ r, Nat.Prime r → r ∣ b → r ∈ R

/-- The block-support primes are coprime to the denominator `b`. -/

def multiGadgetEdges (r : ℕ) (G : Finset ℕ) : Finset ℕ :=
  G.image fun s => r * s

/-- Multiplication by a positive `r` is injective on natural numbers. -/

def residualPairPool {T : Finset ℕ} {b : ℕ} (D : R2ConcreteData T b) :
    Finset ℕ :=
  blockSupportPairPool D.BS \ residualForbidden D

def r2MinorMainCtrlConstant : ℝ :=
  0.8 * (Real.exp (-(Real.pi ^ 2 / 2)) / 2)

/-- Generic scalar budget gate. -/

def blockPart : Finset α :=
  blockMinorPart C.Sm C.Sblock

/-- The remaining covered part assigned to the extra-minor estimate. -/

lemma r2_extra_count_le {T : Finset ℕ} {b : ℕ} (D : R2ConcreteData T b)
    (W : R2ConcreteData.Weights D) (N : ℤ) (C : ℝ)
    (hN : 0 ≤ N)
    (hCN : C / sigmaCtrl D.BS ≤ (N : ℝ))
    (hLeq : D.L = b * ∏ p ∈ blockSupport D.BS, p)
    (MA : MainArcFields D.E W.theta b D.L N) :
    ((extraMinorPart MA.Sm ((mainArcClassificationData D W N C).Sblock MA)
        ((mainArcClassificationData D W N C).Sextra MA)).card : ℝ)
      ≤ (b : ℝ) * (2 * (N : ℝ) + 1) := by
  refine' le_trans ( Nat.cast_le.mpr ( Finset.card_le_card _ ) ) _;
  exact Finset.biUnion ( Finset.Icc ( -N ) N ) fun m => Finset.filter ( fun h => ( fun p : { p // p ∈ blockSupport D.BS } => ( h : ZMod p.1 ) ) = ( fun p : { p // p ∈ blockSupport D.BS } => ( m : ZMod p.1 ) ) ) ( Finset.range D.L );
  · intro h hh; simp_all +decide [ extraMinorPart, mainArcClassificationData ] ;
    unfold mainArcBlockSet mainArcExtraSet at hh; simp_all +decide [ funext_iff ] ;
    obtain ⟨ m, hm₁, hm₂ ⟩ := hh.2.2.2; use m; simp_all +decide [ freqAssignmentOf ] ;
    exact ⟨ ⟨ by exact_mod_cast neg_le_of_abs_le ( hm₁.trans hCN ), by exact_mod_cast le_of_abs_le ( hm₁.trans hCN ) ⟩, by linarith [ Finset.mem_range.mp ( mainArcFields_mem_range_of_mem_Sm MA hh.1 ) ] ⟩;
  · refine' le_trans ( Nat.cast_le.mpr <| Finset.card_biUnion_le ) _;
    refine' le_trans ( Nat.cast_le.mpr <| Finset.sum_le_sum fun x hx => mainArc_fiber_card_le D.BS D.L b hLeq _ ) _ ; norm_num [ Int.card_Icc ] ; ring_nf ; norm_cast ; norm_num [ hN ] ;
    rw [ max_eq_left ] <;> linarith

/-
Strengthened foundation: the explicit dyadic block system (with `P = dyadicBlock`)
additionally exposes that the whole dyadic block at any in-range scale lies in the
support, so high-scale gadget primes can be chosen inside `blockSupport`.
-/

lemma sigmaCtrl_ge_strong (BS : BlockSystem) (hk0 : 14 ≤ BS.k0) :
    (1 : ℝ) / (100 * (BS.k0 : ℝ) * (2 : ℝ) ^ BS.k0) ≤ sigmaCtrl BS := by
  refine Real.le_sqrt_of_sq_le ?_ ; norm_num [ sigmaCtrl ] ; ring;
  refine' le_trans _ ( Finset.sum_le_sum_of_subset_of_nonneg ( show ctrlPairs BS ⊇ internalPairs BS BS.k0 from _ ) fun _ _ _ => by positivity ) <;> norm_num [ pow_mul' ];
  · refine' le_trans _ ( Finset.sum_le_sum fun x hx => show ( x.1 ^ 2 : ℝ ) ⁻¹ * ( x.2 ^ 2 : ℝ ) ⁻¹ ≥ ( 1 / ( 2 ^ ( BS.k0 + 1 ) ) ^ 2 ) ^ 2 from _ ) <;> norm_num [ pow_mul' ] at *;
    · -- Count the number of internal pairs in block `k0`.
      have h_card_internal : (internalPairs BS BS.k0).card ≥ (2 ^ BS.k0 / (2 * (BS.k0 : ℝ) * Real.log 2)) * ((2 ^ BS.k0 / (2 * (BS.k0 : ℝ) * Real.log 2) - 1) / 2) := by
        have h_card_ge : ((internalPairs BS BS.k0).card : ℝ) ≥ (BS.P BS.k0).card * ((BS.P BS.k0).card - 1) / 2 := by
          have h_card_internal : (internalPairs BS BS.k0).card = Finset.card (Finset.powersetCard 2 (BS.P BS.k0)) := by
            refine' Finset.card_bij ( fun x hx => { x.1, x.2 } ) _ _ _ <;> simp_all +decide [ Finset.mem_powersetCard, Finset.subset_iff ];
            · simp +contextual [ internalPairs ];
              exact fun a b ha hb hab => Finset.card_pair hab.ne;
            · simp +contextual [ internalPairs ];
              grind +suggestions;
            · intro b hb hb'; rw [ Finset.card_eq_two ] at hb'; obtain ⟨ a, b, hab, rfl ⟩ := hb'; simp_all +decide [ internalPairs ] ;
              cases lt_or_gt_of_ne hab <;> [ exact ⟨ a, b, ⟨ hb, ‹_› ⟩, rfl ⟩ ; exact ⟨ b, a, ⟨ ⟨ hb.2, hb.1 ⟩, ‹_› ⟩, by rw [ Finset.pair_comm ] ⟩ ];
          rcases n : Finset.card ( BS.P BS.k0 ) with ( _ | _ | n ) <;> simp_all +decide [ Nat.choose_two_right ];
          rw [ Nat.cast_div ] <;> norm_cast ; exact Nat.dvd_of_mod_eq_zero ( by norm_num [ Nat.add_mod, Nat.mod_two_of_bodd ] );
        have h_card_ge : ((BS.P BS.k0).card : ℝ) ≥ (2 ^ BS.k0 / (2 * BS.k0 * Real.log 2)) := by
          have := BS.hdensity BS.k0 ( by linarith ) ( by linarith [ BS.hk ] ) ; simp_all +decide [ Real.log_pow ] ;
          simpa only [ mul_assoc ] using this;
        nlinarith [ show ( 2 : ℝ ) ^ BS.k0 / ( 2 * BS.k0 * Real.log 2 ) ≥ 1 by exact one_le_div ( by positivity ) |>.2 <| by nlinarith [ Real.log_le_sub_one_of_pos zero_lt_two, show ( BS.k0 : ℝ ) ≥ 14 by norm_cast, show ( 2 : ℝ ) ^ BS.k0 ≥ 2 * BS.k0 by exact mod_cast Nat.le_induction ( by norm_num ) ( fun k hk ih ↦ by norm_num [ Nat.pow_succ ] at * ; nlinarith ) _ hk0 ] ];
      refine' le_trans _ ( mul_le_mul_of_nonneg_right h_card_internal _ ) <;> norm_num [ pow_succ' ] at *;
      field_simp;
      refine' Nat.le_induction _ _ BS.k0 hk0 <;> norm_num [ pow_succ' ] at *;
      · have := Real.log_two_lt_d9 ; norm_num at * ; nlinarith [ Real.log_nonneg one_le_two ];
      · intro n hn ih; ring_nf at *; norm_num at *;
        nlinarith [ Real.log_pos one_lt_two, Real.log_le_sub_one_of_pos zero_lt_two, show ( n : ℝ ) ≥ 14 by norm_cast, pow_pos ( zero_lt_two' ℝ ) n ];
    · rw [ ← mul_inv ] ; gcongr ; norm_cast ; simp_all +decide [ internalPairs ];
      · exact ⟨ pow_pos ( Nat.Prime.pos ( by exact BS.hprime _ _ hx.1.1 ) ) 2, pow_pos ( Nat.Prime.pos ( by exact BS.hprime _ _ hx.1.2 ) ) 2 ⟩;
      · norm_cast ; exact Nat.le_trans ( Nat.mul_le_mul ( Nat.pow_le_pow_left ( BS.hwindow BS.k0 x.1 ( Finset.mem_filter.mp hx |>.1 |> Finset.mem_product.mp |>.1 ) |>.2.le ) 2 ) ( Nat.pow_le_pow_left ( BS.hwindow BS.k0 x.2 ( Finset.mem_filter.mp hx |>.1 |> Finset.mem_product.mp |>.2 ) |>.2.le ) 2 ) ) ( by ring_nf; norm_num ) ;
  · exact Finset.subset_iff.mpr fun x hx => Finset.mem_union_left _ <| Finset.mem_biUnion.mpr ⟨ BS.k0, Finset.mem_Icc.mpr ⟨ le_rfl, by linarith [ BS.hk ] ⟩, hx ⟩

/-
Fine main-arc numeric fields for the concrete edge set: with all edges
`≥ Emin`, the label window `N` small relative to `Emin`, and the quadratic
reciprocal-square control `N^2 · ∑ 1/e^2 ≤ 18`, the Taylor conditions `htw`/`hsmall`
hold via the *actual* per-edge sum (not the lossy `card·ρ^3` bound).
-/

lemma r2_numericFields {T : Finset ℕ} {b : ℕ} (D : R2ConcreteData T b)
    (W : R2ConcreteData.Weights D) (N : ℤ) (Emin B : ℝ)
    (hB : 0 < B)
    (he0 : ∀ e ∈ D.E, 0 < e)
    (hEmin0 : 0 < Emin)
    (hEmin : ∀ e ∈ D.E, Emin ≤ (e : ℝ))
    (hN : (1 : ℝ) / Real.sqrt (sigmaE2 D.E W.theta) ≤ (N : ℝ))
    (hNnonneg : 0 ≤ N)
    (h10N : 10 * (N : ℝ) ≤ Emin)
    (hsumsq : (N : ℝ) ^ 2 * (∑ e ∈ D.E, (1 : ℝ) / (e : ℝ) ^ 2) ≤ B)
    (hsmallN : (N : ℝ) / Emin ≤ 1 / (1000000 * B)) :
    MainArcNumericFields D.E W.theta N := by
  refine' ⟨ hN, hNnonneg, _, _ ⟩;
  · intro m hm e he; rw [ abs_div, abs_of_nonneg ( by positivity : ( 0 : ℝ ) ≤ e ) ] ; rw [ div_le_iff₀ ( by norm_cast; linarith [ he0 e he ] ) ] ; ring_nf at *; norm_num at *;
    cases abs_cases ( m : ℝ ) <;> nlinarith [ show ( m : ℝ ) ≥ -N by exact_mod_cast hm.1, show ( m : ℝ ) ≤ N by exact_mod_cast hm.2, show ( e : ℝ ) ≥ Emin by exact_mod_cast hEmin e he ];
  · intro m hm;
    -- For each edge e, |(m:ℝ)/e|^3 ≤ N/Emin * (m^2 * 1/e^2).
    have h_edge_bound : ∀ e ∈ D.E, |(m : ℝ) / e| ^ 3 ≤ (N / Emin) * ((m : ℝ) ^ 2 * (1 / e ^ 2 : ℝ)) := by
      intros e he
      have h_abs : |(m : ℝ) / e| ≤ N / Emin := by
        rw [ abs_div, abs_of_nonneg ( by positivity : ( 0 : ℝ ) ≤ e ) ];
        gcongr <;> norm_cast;
        · exact abs_le.mpr ⟨ by linarith [ Finset.mem_Icc.mp hm ], by linarith [ Finset.mem_Icc.mp hm ] ⟩;
        · exact hEmin e he;
      convert mul_le_mul_of_nonneg_right h_abs ( show 0 ≤ ( m : ℝ ) ^ 2 * ( 1 / e ^ 2 : ℝ ) by positivity ) using 1 ; ring;
      cases abs_cases ( ( m : ℝ ) * ( e : ℝ ) ⁻¹ ) <;> simp +decide [ * ] <;> ring;
    refine' le_trans ( Finset.sum_le_sum fun e he => mul_le_mul_of_nonneg_left ( h_edge_bound e he ) ( by norm_num ) ) _ ; norm_num [ ← Finset.mul_sum _ _ _, ← Finset.sum_mul ] at *;
    refine' le_trans ( mul_le_mul_of_nonneg_left ( mul_le_mul_of_nonneg_left ( mul_le_mul_of_nonneg_right ( show ( m : ℝ ) ^ 2 ≤ N ^ 2 by norm_cast; nlinarith ) <| Finset.sum_nonneg fun _ _ => inv_nonneg.2 <| sq_nonneg _ ) <| by positivity ) <| by positivity ) _;
    nlinarith [ mul_inv_cancel₀ ( ne_of_gt hB ), show ( 0 : ℝ ) ≤ N / Emin by positivity ]

/-
Obtain the residual mass batch `Q` for the high-block gadget set `S`,
discharging the `k0`-large side conditions (`hsum`/`hlarge`/`hTsmall`).
-/

lemma dyadic_block_card_upper (k : ℕ) (hk : 1 ≤ k) :
    (k : ℝ) * ((dyadicBlock k).card : ℝ) ≤ (2 : ℝ) ^ (k + 2) := by
  have h_card : (dyadicBlock k).card * k ≤ 2 ^ (k + 2) := by
    have h_card : (2 ^ k) ^ (dyadicBlock k).card ≤ 4 ^ (2 ^ (k + 1)) := by
      have h_prod : (∏ p ∈ dyadicBlock k, p) ≤ 4 ^ (2 ^ (k + 1)) := by
        refine' le_trans _ ( primorial_le_4_pow ( 2 ^ ( k + 1 ) ) );
        refine' Finset.prod_le_prod_of_subset_of_one_le' _ _ <;> norm_num [ dyadicBlock ];
        · exact fun x hx => Finset.mem_filter.mpr ⟨ Finset.mem_range.mpr ( by linarith [ Finset.mem_Ico.mp ( Finset.mem_filter.mp hx |>.1 ) ] ), Finset.mem_filter.mp hx |>.2 ⟩;
        · exact fun i hi₁ hi₂ hi₃ => Nat.Prime.pos hi₂;
      refine le_trans ?_ h_prod;
      exact le_trans ( by norm_num [ pow_mul ] ) ( Finset.prod_le_prod' fun x hx => show x ≥ 2 ^ k from Finset.mem_filter.mp hx |>.2 |> fun hx' => by linarith [ Finset.mem_Ico.mp ( Finset.mem_filter.mp hx |>.1 ) ] );
    convert Nat.pow_le_pow_iff_right ( show 1 < 2 by norm_num ) |>.1 ( show 2 ^ ( k * #(dyadicBlock k) ) ≤ 2 ^ ( 2 ^ ( k + 2 ) ) from ?_ ) using 1 <;> ring_nf at *;
    exact h_card.trans ( by rw [ show ( 4 : ℕ ) = 2 ^ 2 by norm_num, ← pow_mul ] ; ring_nf; norm_num );
  norm_cast ; linarith

/-
The block-support reciprocal-square sum decays like `2^{-k0}/k0` (using the
prime-counting upper bound).
-/

lemma r2_blockSupport_inv_sq_le (BS : BlockSystem) (hk0 : 1 ≤ BS.k0) :
    ∑ p ∈ blockSupport BS, (1 : ℝ) / (p : ℝ) ^ 2
      ≤ 8 / ((BS.k0 : ℝ) * (2 : ℝ) ^ BS.k0) := by
  have h_sum_le_card : (blockSupport BS).sum (fun p => (1 : ℝ) / p ^ 2) ≤ ∑ k ∈ Finset.Icc BS.k0 BS.K, (dyadicBlock k).card * (1 / (2 ^ k) ^ 2 : ℝ) := by
    have h_sum_le_card : (blockSupport BS).sum (fun p => (1 : ℝ) / p ^ 2) ≤ ∑ k ∈ Finset.Icc BS.k0 BS.K, (BS.P k).sum (fun p => (1 : ℝ) / p ^ 2) := by
      rw [ ← Finset.sum_biUnion ];
      · exact Finset.sum_le_sum_of_subset_of_nonneg ( by aesop_cat ) fun _ _ _ => by positivity;
      · exact fun x hx y hy hxy => blocks_disjoint BS hxy;
    refine le_trans h_sum_le_card <| Finset.sum_le_sum fun k hk => ?_;
    refine' le_trans ( Finset.sum_le_sum fun p hp => one_div_le_one_div_of_le ( by positivity ) <| pow_le_pow_left₀ ( by positivity ) ( show ( p : ℝ ) ≥ 2 ^ k from mod_cast _ ) 2 ) _;
    · exact_mod_cast BS.hwindow k p hp |>.1;
    · simp +zetaDelta at *;
      exact mul_le_mul_of_nonneg_right ( mod_cast Finset.card_le_card <| show BS.P k ⊆ dyadicBlock k from fun x hx => Finset.mem_filter.mpr ⟨ Finset.mem_Ico.mpr <| BS.hwindow k x hx, BS.hprime k x hx ⟩ ) <| by positivity;
  -- Using the upper bound on the cardinality of `dyadicBlock k`, we can further bound the sum.
  have h_card_bound : ∀ k ∈ Finset.Icc BS.k0 BS.K, (dyadicBlock k).card * (1 / (2 ^ k) ^ 2 : ℝ) ≤ 4 / (BS.k0 * 2 ^ k) := by
    intro k hk
    have h_card_bound : (dyadicBlock k).card ≤ (2 ^ (k + 2)) / k := by
      have := dyadic_block_card_upper k ( by linarith [ Finset.mem_Icc.mp hk ] ) ; rw [ Nat.le_div_iff_mul_le ( by linarith [ Finset.mem_Icc.mp hk ] ) ] ; norm_cast at *;
      linarith;
    rw [ mul_one_div, div_le_div_iff₀ ] <;> norm_cast <;> norm_num [ pow_succ' ] at *;
    · exact le_trans ( Nat.mul_le_mul_right _ h_card_bound ) ( by nlinarith [ Nat.div_mul_le_self ( 2 * ( 2 * 2 ^ k ) ) k, pow_pos ( zero_lt_two' ℕ ) k, pow_pos ( zero_lt_two' ℕ ) ( k + 1 ), pow_pos ( zero_lt_two' ℕ ) ( k + 2 ), mul_le_mul_left' hk.1 ( 2 ^ k ) ] );
    · linarith;
  refine le_trans h_sum_le_card <| le_trans ( Finset.sum_le_sum h_card_bound ) ?_;
  erw [ Finset.sum_Ico_eq_sum_range ] ; norm_num [ div_eq_mul_inv, Finset.mul_sum _ _ _, mul_assoc, mul_comm, mul_left_comm, pow_add ] ; ring_nf ; norm_num;
  norm_num [ ← Finset.mul_sum _ _ _, ← Finset.sum_mul ];
  rw [ geom_sum_eq ] <;> ring <;> norm_num

/-- **Light extra edges.**  The mass-batch and gadget edges carry only a bounded
multiple of the control deviation in reciprocal-square mass.  Combined with
`sigmaCtrl_ge_strong`, this yields `σ_E ≤ K·σ_ctrl` with an explicit constant. -/

lemma r2_buildFreqLanes {T : Finset ℕ} {b : ℕ}
    (D : R2ConcreteData T b) (W : R2ConcreteData.Weights D) (N : ℤ)
    (C η Ctail Dmp : ℝ) (G : ℕ)
    (hbpos : 0 < b) (hsqfree : Squarefree b)
    (hcovR : CoversPrimeDivisors D.R b) (hcopB : BlockSupportCoprimeWith D.BS b)
    (hRprime : ∀ r ∈ D.R, Nat.Prime r) (hSprime : ∀ s ∈ D.S, Nat.Prime s)
    (hRdvd : ∀ r ∈ D.R, r ∣ b) (hSblock : D.S ⊆ blockSupport D.BS)
    (hlt : ∀ r ∈ D.R, ∀ s ∈ D.S, r < s)
    (hctrlAvoid : ∀ e ∈ ctrlEdges D.BS, e ∉ T)
    (hgadgetAvoid : ∀ e ∈ gadgetEdges D.R D.S, e ∉ T)
    (heL : ∀ e ∈ D.E, e ∣ D.L) (he0 : ∀ e ∈ D.E, 0 < e) (hL : 0 < D.L)
    (hLeq : D.L = b * ∏ p ∈ blockSupport D.BS, p)
    (hC : 1 ≤ C) (hNnonneg : 0 ≤ N)
    (hSge : ∀ s ∈ D.S, 2 ^ (2 * D.BS.k0) ≤ s) (hScard : D.S.card = G)
    (hCN : C / sigmaCtrl D.BS ≤ (N : ℝ))
    (hN2 : 2 * N < (2 : ℤ) ^ (2 * D.BS.k0))
    (hDmpnn : 0 ≤ Dmp)
    (hG : (Real.sqrt (1 - (8 / 9) / (b : ℝ) ^ 2)) ^ G ≤ Dmp) :
    Nonempty (R2MinorEndgameFrequencyLanes D W N
      ((b : ℝ) * (η + Ctail * Real.exp (-C ^ 2 * (16 / 9) / 2)) / sigmaCtrl D.BS)
      ((b : ℝ) * (2 * (N : ℝ) + 1) * Dmp) η Ctail (N : ℝ) Dmp
      (mainArcClassificationData D W N C)) := by
  constructor;
  apply_rules [ R2MinorEndgameFrequencyLanes.mk ];
  use by norm_cast;
  exact le_mul_of_one_le_right ( by positivity ) ( mod_cast Nat.one_le_iff_ne_zero.mpr <| by positivity );
  exact 1;
  exact le_mul_of_one_le_right ( by positivity ) ( mod_cast Nat.one_le_iff_ne_zero.mpr <| by positivity );
  exact fun r hr => Nat.Prime.pos ( hRprime r hr );
  exact fun MA => by
