lemma sigmaP_upper (X : ℕ) (hX : 1 ≤ X) (P : Finset ℕ)
    (hP : ∀ p ∈ P, Nat.Prime p ∧ X ≤ p ∧ p ≤ 2*X) :
    sigmaP P ≤ (P.card:ℝ)/(X:ℝ)^2 := by
