/-
**Mesh `R_C ≤ R_w` (asymptotic).**  For `X` large the fingerprint threshold
    `Cε·X^{2/3}(log X)^{4/3}` is below the window floor `cp·X/(log X)³`.
-/

lemma mesh_lemma (cp Ceps : ℝ) (hcp : 0 < cp) (hCeps : 0 < Ceps) :
    ∃ X1 : ℝ, 0 < X1 ∧ ∀ X : ℕ, X1 ≤ X →
      Ceps*(X:ℝ)^((2:ℝ)/3)*(Real.log X)^((4:ℝ)/3) ≤ cp*(X:ℝ)/(Real.log X)^3 := by
  obtain ⟨X1, hX1⟩ : ∃ X1 : ℝ, 0 < X1 ∧ ∀ X : ℕ, X1 ≤ X → Ceps^3 * (X : ℝ)^2 * (Real.log X)^4 ≤ cp^3 * (X : ℝ)^3 / (Real.log X)^9 := by
    obtain ⟨ X1, hX1 ⟩ := logthreshold_pow 13 ( Ceps^3 / cp^3 );
    refine' ⟨ Max.max X1 3, _, _ ⟩ <;> norm_num;
    intro X hX₁ hX₂; have := hX1.2 X hX₁; rw [ div_le_div_iff₀ ] at this;
    · rw [ le_div_iff₀ ( pow_pos ( Real.log_pos ( by norm_cast; linarith ) ) _ ) ] ; nlinarith [ show ( X : ℝ ) ^ 3 > 0 by positivity ] ;
    · positivity;
    · exact pow_pos ( Real.log_pos ( by norm_cast; linarith ) ) _;
  refine' ⟨ Max.max X1 3, by positivity, fun X hX => _ ⟩ ; specialize hX1 ; replace hX1 := hX1.2 X ( le_trans ( le_max_left _ _ ) hX ) ; norm_num at *;
  contrapose! hX1;
  convert pow_lt_pow_left₀ hX1 ( div_nonneg ( mul_nonneg hcp.le ( Nat.cast_nonneg _ ) ) ( pow_nonneg ( Real.log_nonneg ( Nat.one_le_cast.mpr ( by linarith ) ) ) _ ) ) three_ne_zero using 1 <;> ring;
  norm_num only [ ← Real.rpow_natCast, ← Real.rpow_mul ( Nat.cast_nonneg _ ), ← Real.rpow_mul ( Real.log_nonneg ( Nat.one_le_cast.mpr ( by linarith ) ) ) ]

/-
**Unified level-set bound.**  Combining Theorem A+B (below the window, via
    `corollary_SBEE_below_window`) and Theorem C (`fingerprint_count`, above the
    window) through the mesh, every level set is bounded by
    `C₀·e^{εR}·(1 + √R/σ_P)` for all `R ≥ 1`.
-/
set_option maxHeartbeats 1000000 in

lemma unified_levelset (eps : ℝ) (hε0 : 0 < eps) (hε1 : eps < 1) :
    ∃ (C0 X1 : ℝ), 0 < C0 ∧ 0 < X1 ∧
      ∀ (X : ℕ), X1 ≤ X →
        ∀ (P : Finset ℕ) [∀ p : P, NeZero p.1]
          (hP : ∀ p ∈ P, Nat.Prime p ∧ X ≤ p ∧ p ≤ 2*X)
          (hN : (X:ℝ)/(2 * Real.log X) ≤ P.card)
          (R : ℝ), 1 ≤ R →
            ((Finset.univ.filter (fun a : BlockAssignment P => QP P a ≤ R)).card : ℝ)
              ≤ C0 * Real.exp (eps*R) * (1 + Real.sqrt R / sigmaP P) := by
  -- Apply the provided solution to obtain the constants `C0` and `X1`.
  obtain ⟨cp, X0c, hcp, hX0c, Hcor⟩ := SBEEForcing.corollary_SBEE_below_window eps hε0 (1/4) (by norm_num) (by norm_num)
  obtain ⟨Ceps, X0f, hCeps, hX0f, Hfp⟩ := SBEEFingerprint.fingerprint_count eps hε0 hε1
  obtain ⟨Xm, hXm0, hmesh⟩ := mesh_lemma cp Ceps hcp hCeps
  obtain ⟨X16, hX160, hX16⟩ := logthreshold_pow 3 (16/cp)
  obtain ⟨Xc2, hXc20, hXc2⟩ := logthreshold_pow 1 4;
  refine' ⟨ 20, Max.max ( Max.max X0c X0f ) ( Max.max Xm ( Max.max X16 ( Max.max Xc2 3 ) ) ), _, _, _ ⟩ <;> norm_num;
  intro X hX0c hX0f hXm hX16 hXc2 hX3 P inst hP hN R hR1
  by_cases hRle : R ≤ cp * X / (Real.log X)^3;
  · convert le_trans ( Hcor X hX0c P hP hN R hR1 hRle ) _ using 1;
    ring_nf;
    linarith [ Real.exp_pos ( eps * R ) ];
  · have hRC : Ceps * X ^ ((2 : ℝ) / 3) * (Real.log X) ^ ((4 : ℝ) / 3) ≤ R := by
      exact le_trans ( hmesh X hXm ) ( le_of_not_ge hRle );
    have hNsqrt : (P.card : ℝ) ≤ Real.sqrt R / sigmaP P := by
      have hNsqrt : (P.card : ℝ) ≤ Real.sqrt R / sigmaP P := by
        have hσub : sigmaP P ≤ (P.card : ℝ) / (X : ℝ)^2 := by
          convert sigmaP_upper X ( by linarith ) P hP using 1
        have hN2X : (P.card : ℝ) ≤ 2 * X := by
          exact_mod_cast SBEEFingerprint.block_card_le_two_mul X P hP
        have hR16 : (16 : ℝ) ≤ R := by
          rename_i hX16' hXc2';
          have := hX16' X hX16; rw [ div_le_iff₀ ( by positivity ) ] at this; ring_nf at *; nlinarith;
        have hNsqrt : (P.card : ℝ) * sigmaP P ≤ Real.sqrt R := by
          refine le_trans ( mul_le_mul_of_nonneg_left hσub <| Nat.cast_nonneg _ ) ?_;
          rw [ mul_div, div_le_iff₀ ] <;> try positivity;
          exact le_trans ( mul_le_mul hN2X hN2X ( by positivity ) ( by positivity ) ) ( by nlinarith [ Real.sqrt_nonneg R, Real.sq_sqrt ( show 0 ≤ R by positivity ), show ( X : ℝ ) ^ 2 ≥ 0 by positivity ] );
        rwa [ le_div_iff₀ ( show 0 < sigmaP P from _ ) ];
        apply sigmaP_pos_of_two;
        · exact fun p hp => hP p hp |>.1;
        · contrapose! hN;
          interval_cases _ : #P <;> norm_num at *;
          · exact div_pos ( by positivity ) ( mul_pos zero_lt_two ( Real.log_pos ( by norm_cast; linarith ) ) );
          · rw [ lt_div_iff₀ ( mul_pos zero_lt_two ( Real.log_pos ( by norm_cast; linarith ) ) ) ];
            have := Real.log_lt_sub_one_of_pos ( by positivity : 0 < ( X : ℝ ) / 2 );
            rw [ Real.log_div ( by positivity ) ( by positivity ) ] at this;
            linarith [ this ( by linarith [ show ( X : ℝ ) ≥ 3 by norm_cast ] ), Real.log_le_sub_one_of_pos zero_lt_two ];
      exact hNsqrt;
    have hNsqrt : (P.card : ℝ) * Real.exp (eps * R) ≤ 20 * Real.exp (eps * R) * (1 + Real.sqrt R / sigmaP P) := by
      nlinarith [ Real.exp_pos ( eps * R ), show 0 ≤ Real.sqrt R / sigmaP P by exact div_nonneg ( Real.sqrt_nonneg _ ) ( show 0 ≤ sigmaP P by exact Real.sqrt_nonneg _ ) ];
    refine le_trans ?_ hNsqrt;
    convert Hfp X hX0f P hP _ R hRC using 1;
    exact Nat.cast_pos.mp ( lt_of_lt_of_le ( by exact div_pos ( Nat.cast_pos.mpr ( by linarith ) ) ( mul_pos zero_lt_two ( Real.log_pos ( by norm_cast; linarith ) ) ) ) hN )

/-
**Partition function from a level-set bound (Laplace / dyadic series).**
    A finite Gaussian sum `∑ exp(-c·qᵢ)` is controlled by a level-set bound
    `#{qᵢ ≤ R} ≤ C₀·e^{εR}·(1 + √R/σ)` (for `R ≥ 1`, `ε < c`) via a geometric
    majorant.
-/
set_option maxHeartbeats 1000000 in

lemma partfun_series_bound {ι : Type*} [Fintype ι] (q : ι → ℝ) (hq : ∀ i, 0 ≤ q i)
    (c eps C0 sig : ℝ) (hc : 0 < c) (hε0 : 0 ≤ eps) (hεc : eps < c)
    (hC0 : 0 ≤ C0) (hsig : 0 < sig)
    (hlevel : ∀ R : ℝ, 1 ≤ R →
        ((Finset.univ.filter (fun i => q i ≤ R)).card : ℝ)
          ≤ C0 * Real.exp (eps*R) * (1 + Real.sqrt R / sig)) :
    ∑ i, Real.exp (-c * q i)
      ≤ C0 * Real.exp eps / (1 - Real.exp (-(c-eps)))^2 * (1 + 1/sig) := by
  -- Let $r := \exp(-(c-\epsilon))$; since $c-\epsilon > 0$, $0 < r < 1$.
  set r := Real.exp (-(c - eps)) with hr
  have hr_pos : 0 < r := by
    positivity
  have hr_lt_1 : r < 1 := by
    exact Real.exp_lt_one_iff.mpr ( neg_lt_zero.mpr ( sub_pos.mpr hεc ) );
  -- For each $i$, $\exp(-c q_i) \leq \exp(-c \lfloor q_i \rfloor)$ since $q_i \geq \lfloor q_i \rfloor \geq 0$ and $c > 0$.
  have h_floor_dom : ∑ i, Real.exp (-c * q i) ≤ ∑ m ∈ Finset.image (fun i => Nat.floor (q i)) Finset.univ, Real.exp (-c * m) * (Finset.card (Finset.filter (fun i => Nat.floor (q i) = m) Finset.univ)) := by
    have h_floor_dom : ∀ i, Real.exp (-c * q i) ≤ Real.exp (-c * (Nat.floor (q i) : ℝ)) := by
      exact fun i => Real.exp_le_exp.mpr ( mul_le_mul_of_nonpos_left ( Nat.floor_le ( hq i ) ) ( neg_nonpos.mpr hc.le ) );
    refine' le_trans ( Finset.sum_le_sum fun i _ => h_floor_dom i ) _;
    rw [ Finset.sum_image' ] ; simp +decide [ mul_comm ];
    intro i; rw [ Finset.sum_congr rfl fun j hj => by rw [ Finset.mem_filter.mp hj |>.2 ] ] ; simp +decide [ mul_comm ] ;
  -- For each $m$, the cardinality of the fiber $\{i : \lfloor q_i \rfloor = m\}$ is at most $C_0 \exp(\epsilon(m+1))(1 + (m+1)/\sigma)$.
  have h_fiber_bound : ∀ m : ℕ, (Finset.card (Finset.filter (fun i => Nat.floor (q i) = m) Finset.univ)) ≤ C0 * Real.exp (eps * (m + 1)) * (1 + (m + 1) / sig) := by
    intro m
    have h_fiber_bound_step : (Finset.card (Finset.filter (fun i => q i ≤ m + 1) Finset.univ)) ≤ C0 * Real.exp (eps * (m + 1)) * (1 + (m + 1) / sig) := by
      refine' le_trans ( hlevel ( m + 1 ) ( by linarith ) ) _;
      gcongr;
      exact Real.sqrt_le_iff.mpr ⟨ by positivity, by nlinarith ⟩;
    refine' le_trans _ h_fiber_bound_step;
    gcongr;
    exact fun h => by linarith [ Nat.lt_floor_add_one ( q ‹_› ), show ( ⌊q ‹_›⌋₊ : ℝ ) = m by exact_mod_cast h ] ;
  -- So $\sum_{i} \exp(-c q_i) \leq \sum_{m} \exp(-c m) C_0 \exp(\epsilon(m+1))(1 + (m+1)/\sigma) = C_0 \exp(\epsilon) \sum_{m} r^m (1 + (m+1)/\sigma)$.
  have h_sum_bound : ∑ i, Real.exp (-c * q i) ≤ C0 * Real.exp eps * ∑' m : ℕ, r^m * (1 + (m + 1) / sig) := by
    have h_sum_bound : ∑ i, Real.exp (-c * q i) ≤ C0 * Real.exp eps * ∑ m ∈ Finset.image (fun i => Nat.floor (q i)) Finset.univ, r^m * (1 + (m + 1) / sig) := by
      refine le_trans h_floor_dom ?_;
      rw [ Finset.mul_sum _ _ _ ] ; refine' Finset.sum_le_sum fun m hm => _ ; specialize h_fiber_bound m ; simp_all +decide [ Real.exp_add, Real.exp_neg, mul_assoc, mul_comm, mul_left_comm, pow_add ] ;
      convert mul_le_mul_of_nonneg_left h_fiber_bound ( inv_nonneg.2 ( Real.exp_nonneg ( c * m ) ) ) using 1 ; ring;
      norm_num [ ← Real.exp_nat_mul, ← Real.exp_neg, ← Real.exp_add ] ; ring;
      simpa only [ mul_assoc, ← Real.exp_add ] using by ring;
    refine' le_trans h_sum_bound ( mul_le_mul_of_nonneg_left ( Summable.sum_le_tsum _ _ _ ) ( by positivity ) );
    · exact fun _ _ => by positivity;
    · have h_summable : Summable (fun m : ℕ => r^m * (m + 1)) := by
        refine' summable_of_ratio_norm_eventually_le _ _;
        exact ( 1 + r ) / 2;
        · grind;
        · norm_num [ pow_succ', mul_assoc, abs_of_pos hr_pos ];
          exact ⟨ ⌈ ( 1 + r ) / ( 1 - r ) ⌉₊ + 1, fun n hn => by rw [ abs_of_nonneg ( by positivity ), abs_of_nonneg ( by positivity ) ] ; nlinarith [ Nat.le_ceil ( ( 1 + r ) / ( 1 - r ) ), show ( n : ℝ ) ≥ ⌈ ( 1 + r ) / ( 1 - r ) ⌉₊ + 1 by exact_mod_cast hn, pow_nonneg hr_pos.le n, mul_le_mul_of_nonneg_right ( show ( r : ℝ ) ≤ 1 by linarith ) ( pow_nonneg hr_pos.le n ), mul_div_cancel₀ ( 1 + r ) ( by linarith : ( 1 - r ) ≠ 0 ) ] ⟩;
      convert h_summable.mul_right ( 1 / sig ) |> Summable.add <| summable_geometric_of_lt_one hr_pos.le hr_lt_1 using 2 ; ring;
  -- Evaluate the geometric series $\sum_{m=0}^{\infty} r^m (1 + (m+1)/\sigma)$.
  have h_geo_series : ∑' m : ℕ, r^m * (1 + (m + 1) / sig) = (1 / (1 - r)) + (1 / sig) * (1 / (1 - r)^2) := by
    have h_geo_series : ∑' m : ℕ, r^m * (m + 1) = 1 / (1 - r)^2 := by
      have h_geo_series : HasSum (fun m : ℕ => r^m * (m + 1)) (1 / (1 - r)^2) := by
        have h_geo_series : HasSum (fun m : ℕ => (m : ℝ) * r^m) (r / (1 - r)^2) := by
          have := tsum_coe_mul_geometric_of_norm_lt_one ( show ‖r‖ < 1 from by simpa [ abs_of_pos hr_pos ] using hr_lt_1 );
          exact this ▸ Summable.hasSum ( by exact ( by contrapose! this; erw [ tsum_eq_zero_of_not_summable this ] ; exact ne_of_lt ( div_pos hr_pos ( sq_pos_of_pos ( sub_pos.mpr hr_lt_1 ) ) ) ) );
        convert HasSum.add ( hasSum_geometric_of_lt_one hr_pos.le hr_lt_1 ) h_geo_series using 1 <;> ring;
        grind;
      exact h_geo_series.tsum_eq;
    convert congr_arg₂ ( · + · ) ( tsum_geometric_of_lt_one hr_pos.le hr_lt_1 ) ( congr_arg ( fun x : ℝ => x / sig ) h_geo_series ) using 1 <;> ring;
    rw [ ← tsum_mul_left ] ; rw [ ← Summable.tsum_add ] ; congr ; ext m ; ring;
    · refine' Summable.mul_left _ _;
      refine' Summable.add ( summable_geometric_of_lt_one hr_pos.le hr_lt_1 ) _;
      contrapose! h_geo_series;
      rw [ tsum_eq_zero_of_not_summable ] <;> norm_num;
      · nlinarith;
      · exact fun h => h_geo_series <| Summable.of_nonneg_of_le ( fun m => by positivity ) ( fun m => by exact mul_le_mul_of_nonneg_left ( by linarith ) ( by positivity ) ) h;
    · exact summable_geometric_of_lt_one hr_pos.le hr_lt_1;
  refine le_trans h_sum_bound ?_;
  rw [ h_geo_series ] ; ring_nf;
  rw [ add_comm ] ; gcongr; all_goals nlinarith only [ hr_pos, hr_lt_1 ]

/-
**Single-block counting = SBEE** (`30 §2`, assembled).
-/

theorem single_block_counting (c : ℝ) (hc : 0 < c) :
    SBEEPartitionBound c := by
  -- Set eps := min (c/2) (1/2). Then 0<eps, eps<c (eps≤c/2<c), eps<1 (eps≤1/2<1), and c-eps>0.
  set eps := min (c / 2) (1 / 2)
  have hε0 : 0 < eps := by
    positivity
  have hεc : eps < c := by
    exact lt_of_le_of_lt ( min_le_left _ _ ) ( half_lt_self hc )
  have hε1 : eps < 1 := by
    exact lt_of_le_of_lt ( min_le_right _ _ ) ( by norm_num );
  obtain ⟨ C0, X1, hC0, hX1, Huni ⟩ := SBEEAssembly.unified_levelset eps hε0 hε1;
  -- Set K := C0 * Real.exp eps / (1 - Real.exp (-(c-eps)))^2.
  set K := C0 * Real.exp eps / (1 - Real.exp (-(c-eps)))^2 with hK_def;
  -- Set M := ⌈X1⌉₊.
  set M := Nat.ceil X1 with hM_def;
  refine' ⟨ Max.max ( 3 * K ) ( ( 2 * ( M : ℝ ) ) ^ ( 2 * M ) * 2 + 1 ), _, _ ⟩ <;> norm_num;
  · exact Or.inr ( by positivity );
  · intro P hP hIrv hcard2
    obtain ⟨X, hX0, hPrange, hNbound⟩ := hIrv
    haveI : ∀ p : P, NeZero p.1 := fun p => ⟨(hP p.1 p.2).ne_zero⟩
    have hX1nat : 1 ≤ X := hX0
    have hσpos : 0 < sigmaP P := sigmaP_pos_of_two P hP hcard2
    have hσub : sigmaP P ≤ (P.card:ℝ)/(X:ℝ)^2 := sigmaP_upper X hX1nat P hPrange
    have hN2X : (P.card:ℝ) ≤ 2*X := by exact_mod_cast SBEEFingerprint.block_card_le_two_mul X P hPrange
    have hXr1 : (1:ℝ) ≤ X := by exact_mod_cast hX1nat
    have hσ2 : sigmaP P ≤ 2 := le_trans hσub (by rw [div_le_iff₀ (by positivity)]; nlinarith [hN2X, hXr1]);
    by_cases hXbig : X1 ≤ (X:ℝ);
    · have hlevel : ∀ R:ℝ, 1≤R → ((Finset.univ.filter (fun a:BlockAssignment P => QP P a ≤ R)).card:ℝ) ≤ C0*Real.exp (eps*R)*(1+Real.sqrt R/sigmaP P) := fun R hR => Huni X hXbig P hPrange hNbound R hR;
      have hser := partfun_series_bound (fun a:BlockAssignment P => QP P a) (fun a => QP_nonneg P a) c eps C0 (sigmaP P) hc (by positivity) (lt_of_le_of_lt (min_le_left _ _) (by linarith)) hC0.le hσpos hlevel;
      have hKge : blockPartFun P hP c ≤ K * (1 + 1 / sigmaP P) := by
        convert hser using 1;
      rw [ le_div_iff₀ hσpos ];
      refine le_trans ?_ ( le_max_left _ _ );
      nlinarith [ mul_div_cancel₀ 1 hσpos.ne', show 0 ≤ K by exact div_nonneg ( mul_nonneg hC0.le ( Real.exp_nonneg _ ) ) ( sq_nonneg _ ) ];
    · have hbpf_le : blockPartFun P hP c ≤ (2*(X:ℝ))^P.card := by
        refine' le_trans ( Finset.sum_le_sum fun a _ => Real.exp_le_one_iff.mpr _ ) _ <;> norm_num;
        · exact mul_nonneg hc.le ( QP_nonneg P a );
        · exact le_trans ( Finset.prod_le_prod ( fun _ _ => Nat.cast_nonneg _ ) fun _ _ => show ( _ : ℝ ) ≤ 2 * X from mod_cast hPrange _ ( Subtype.mem _ ) |>.2.2 ) ( by norm_num );
      have hXM : X ≤ M := by
        exact Nat.le_of_lt_succ ( by rw [ ← @Nat.cast_lt ℝ ] ; push_cast; linarith [ Nat.le_ceil X1 ] );
      have hb : blockPartFun P hP c ≤ (2*(M:ℝ))^(2*M) := by
        refine le_trans hbpf_le ?_;
        exact le_trans ( pow_le_pow_left₀ ( by positivity ) ( mul_le_mul_of_nonneg_left ( Nat.cast_le.mpr hXM ) zero_le_two ) _ ) ( pow_le_pow_right₀ ( by linarith [ show ( M : ℝ ) ≥ 1 by exact Nat.one_le_cast.mpr ( Nat.ceil_pos.mpr hX1 ) ] ) ( by linarith [ show ( P.card : ℕ ) ≤ 2 * X by exact_mod_cast hN2X ] ) );
      rw [ le_div_iff₀ hσpos ];
      exact le_trans ( mul_le_mul_of_nonneg_left hσ2 <| by exact Finset.sum_nonneg fun _ _ => Real.exp_nonneg _ ) <| by nlinarith [ le_max_right ( 3 * K ) ( ( 2 * M : ℝ ) ^ ( 2 * M ) * 2 + 1 ) ] ;

end SBEEAssembly

theorem lemmaD (X q U : ℕ) (hq : q.Prime) (hXq : X ≤ q) (_hUX : U < X)
    (w : ℤ) (hw : ¬ (q:ℤ) ∣ w) :
    (lemmaD_set X q U w).card ≤ 2 * (2 * U + 1) := by
  have key : ∀ u ∈ Finset.Icc (-(U:ℤ)) U, (Finset.filter (fun up => up.1 = u) (lemmaD_set X q U w)).card ≤ 2 := by
    intro u _hu;
    -- The fiber {x ∈ S : x.1 = u} is in bijection with the p-fiber {p ∈ Icc X (2X) : p.Prime ∧ (q:ℤ) ∣ (u·p - w)} via p ↦ (u,p).
    have h_bij : Finset.filter (fun up => up.1 = u) (lemmaD_set X q U w) ⊆ Finset.image (fun p : ℕ => (u, p)) (Finset.filter (fun p => Nat.Prime p ∧ (q:ℤ) ∣ (u * (p : ℤ) - w)) (Finset.Icc X (2 * X))) := by
      grind +locals;
    refine le_trans ( Finset.card_le_card h_bij ) ?_;
    rw [ Finset.card_image_of_injective _ fun x y hxy => by injection hxy ];
    exact lemmaD_fiber X q hq hXq w hw u;
  convert Finset.sum_le_sum key using 1;
  · rw [ ← Finset.card_eq_sum_card_fiberwise ];
    exact fun x hx => Finset.mem_Icc.mpr <| Finset.mem_Icc.mp <| Finset.mem_product.mp ( Finset.mem_filter.mp hx |>.1 ) |>.1;
  · norm_num [ two_mul, add_assoc ];
    grind

/-! ## The dispersion corollary — `30 §1`, "Dispersion (Lemma D form)"

For `q ∉ F`, integer `E` with `q ∤ E`, `0 < |E| < q`, and `δ = |F|/(32X)`:
`#{p ∈ F : ‖E·q̄/p‖ ≤ δ} ≤ 2·(4δX+1) ≤ |F|/2`, hence
`∑_{p ∈ F} ‖E·q̄/p‖² ≥ |F|³/(2^11 X²) =: G_F`.

These statements require the fractional-norm `‖·‖` on `ℝ/ℤ` together with the
modular inverse `q̄` mod `p`; they are stated abstractly here with a real-valued
"reciprocal phase" function `phase` and isolated as `sorry`.  The mathematical
content reduces to `lemmaD` via `p ∣ E - u·q`. -/

/-- Reciprocal phase `‖E·q̄/p‖ ∈ [0, 1/2]`: the distance to the nearest integer of
    `E · q̄ / p`, where `q̄ = (q : ZMod p)⁻¹` is the modular inverse of `q` mod `p`.
    This is the faithful fractional-norm used in `30 §1`. -/
noncomputable def phase (E : ℤ) (q p : ℕ) : ℝ :=
  let x : ℝ := (E : ℝ) * (((q : ZMod p)⁻¹).val : ℝ) / (p : ℝ)
  |x - (round x : ℝ)|

/-- `phase` is nonnegative. -/

lemma phase_neg (E : ℤ) (q p : ℕ) : phase (-E) q p = phase E q p := by
  unfold phase;
  norm_num [ round_eq ];
  rw [ neg_div, abs_sub_comm ];
  rw [ show ( - ( ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val / p ) + 1 / 2 : ℝ ) = - ( ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val / p + 1 / 2 ) + 1 by ring ] ; norm_num [ Int.floor_neg ] ; ring;
  rw [ show ( -1 / 2 - ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ) = - ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ) by ring, Int.floor_neg ] ; ring; norm_num;
  rw [ show ( ⌈1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹⌉ : ℤ ) = ⌊1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹⌋ + if ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ) ≤ ⌊1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹⌋ then 0 else 1 from ?_ ] ; split_ifs <;> norm_num ; ring;
  · rw [ abs_of_nonneg, abs_of_nonpos ] <;> linarith [ Int.floor_le ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ), Int.lt_floor_add_one ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ) ];
  · ring;
  · split_ifs <;> norm_num [ Int.ceil_eq_iff ] at * <;> constructor <;> linarith [ Int.floor_le ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ), Int.lt_floor_add_one ( 1 / 2 + ( E : ℝ ) * ( q : ZMod p ) ⁻¹.val * ( p : ℝ ) ⁻¹ ) ] ;

/-
**Fractional-norm triangle inequality** for the reciprocal phase:
    `‖(A−B)q̄/p‖ ≤ ‖A q̄/p‖ + ‖B q̄/p‖`.

    This is the analytic mechanism behind **cold rigidity** (`30 §1`): with
    `A = a_p − w̃`, `B = a_p − w̃'`, the difference `A − B = w̃' − w̃ = E`, so
    `‖E q̄/p‖ ≤ ‖A q̄/p‖ + ‖B q̄/p‖`; summing the squares and applying
    `dispersion_energy_bound` to `E` yields the two-cold-residue contradiction.

    Proof: with `x_E := E·q̄/p`, linearity gives `x_{A−B} = x_A − x_B`.  Writing
    `k := round x_A − round x_B ∈ ℤ`, the nearest-integer minimality `round_le`
    gives `|x_{A−B} − round x_{A−B}| ≤ |x_{A−B} − k| = |(x_A − round x_A) −
    (x_B − round x_B)| ≤ |x_A − round x_A| + |x_B − round x_B|`.
-/

lemma card_prime_factors_dyadic_le_two (X : ℕ) (n : ℤ) (hn : n ≠ 0)
    (hX : |n| < (X:ℤ)^3) :
    ((Finset.Icc X (2*X)).filter (fun p => Nat.Prime p ∧ (p:ℤ) ∣ n)).card ≤ 2 := by
  by_contra h_contra;
  obtain ⟨a, b, c, ha, hb, hc, habc⟩ : ∃ a b c : ℕ, a ∈ Finset.Icc X (2 * X) ∧ b ∈ Finset.Icc X (2 * X) ∧ c ∈ Finset.Icc X (2 * X) ∧ Nat.Prime a ∧ Nat.Prime b ∧ Nat.Prime c ∧ a ∣ Int.natAbs n ∧ b ∣ Int.natAbs n ∧ c ∣ Int.natAbs n ∧ a ≠ b ∧ a ≠ c ∧ b ≠ c := by
    obtain ⟨ s, hs ⟩ := Finset.two_lt_card.mp ( by linarith ) ; simp_all +decide ;
    rcases hs with ⟨ ⟨ ⟨ hs₁, hs₂ ⟩, hs₃, hs₄ ⟩, b, ⟨ ⟨ hb₁, hb₂ ⟩, hb₃, hb₄ ⟩, c, ⟨ ⟨ hc₁, hc₂ ⟩, hc₃, hc₄ ⟩, hbc ⟩ ; use s, ⟨ hs₁, hs₂ ⟩, b, ⟨ hb₁, hb₂ ⟩, c, ⟨ hc₁, hc₂ ⟩ ; simp_all +decide [ ← Int.natCast_dvd_natCast ] ;
  -- Since $a$, $b$, and $c$ are pairwise coprime primes dividing $n$, their product $a \cdot b \cdot c$ also divides $n$.
  have h_prod_div : (a * b * c : ℤ) ∣ n.natAbs := by
    norm_cast;
    apply_mod_cast Nat.Coprime.mul_dvd_of_dvd_of_dvd;
    · simp_all +decide [ Nat.coprime_mul_iff_left, Nat.coprime_primes ];
    · exact Nat.Coprime.mul_dvd_of_dvd_of_dvd ( by have := Nat.coprime_primes habc.1 habc.2.1; aesop ) habc.2.2.2.1 habc.2.2.2.2.1;
    · tauto;
  have h_prod_ge : (a * b * c : ℤ) ≥ X^3 := by
    norm_cast;
    exact le_trans ( by ring_nf; norm_num ) ( Nat.mul_le_mul ( Nat.mul_le_mul ( Finset.mem_Icc.mp ha |>.1 ) ( Finset.mem_Icc.mp hb |>.1 ) ) ( Finset.mem_Icc.mp hc |>.1 ) );
  exact not_lt_of_ge ( Int.le_of_dvd ( by positivity ) h_prod_div ) ( by simpa [ abs_mul ] using hX.trans_le h_prod_ge )

/-
**Phase → divisibility witness** (the bridge of `30 §1` / `31 §4`).  If the
    reciprocal phase `‖E·q̄/p‖ = phase E q p` is `≤ δ`, then there is an integer
    `s` with `|s| ≤ 2δX` and `p ∣ E − s·q`.

    Construction: with `q̄ = (q : ZMod p)⁻¹.val` and `r = round (E·q̄/p)`, set
    `s = E·q̄ − r·p`.  Then `|s| = p·phase ≤ p·δ ≤ 2X·δ`, and modulo `p`,
    `s ≡ E·q̄`, so `s·q ≡ E·(q̄·q) ≡ E` (using `q·q̄ ≡ 1 (mod p)`, valid as
    `p ∤ q` for distinct primes `p ≠ q`); hence `p ∣ E − s·q`.
-/

theorem dispersion_residue_count
    (X : ℕ) (F : Finset ℕ) (hF : ∀ p ∈ F, Nat.Prime p ∧ X ≤ p ∧ p ≤ 2*X)
    (hFcard : 8 ≤ F.card)
    (q : ℕ) (hq : q.Prime) (hqF : q ∉ F) (hq2X : q ≤ 2*X) (E : ℤ)
    (hqE : ¬ (q:ℤ) ∣ E) (_hE0 : 0 < |E|) (hEq : |E| < (q:ℤ)) :
    ((F.filter (fun p => phase E q p ≤ (F.card : ℝ) / (32 * X))).card : ℝ)
      ≤ (F.card : ℝ) / 2 := by
  -- Let m : ℤ := ⌊2*δ*(X:ℝ)⌋; then m ≥ 0 and (m:ℝ) ≤ 2*δ*X. Let T : Finset ℤ := Finset.Icc (-m) m; its card is (2*m+1).toNat and (T.card : ℝ) ≤ 2*(2*δ*X) + 1 = 4*δ*X + 1.
  set δ : ℝ := (F.card : ℝ) / (32 * X)
  set m : ℤ := ⌊2 * δ * (X : ℝ)⌋
  set T : Finset ℤ := Finset.Icc (-m) m;
  -- Apply `card_prime_factors_dyadic_le_two` to bound the cardinality of the filter.
  have : ((F.filter (fun p => phase E q p ≤ δ)).card : ℝ) ≤ 2 * T.card := by
    have h_cover : F.filter (fun p => phase E q p ≤ δ) ⊆ T.biUnion (fun s => F.filter (fun p => (p : ℤ) ∣ (E - s * q))) := by
      intro p hp; simp_all +decide ;
      obtain ⟨ s, hs₁, hs₂ ⟩ := phase_dvd_witness X p q ( hF p hp.1 |>.1 ) ( hF p hp.1 |>.2.2 ) hq ( by aesop ) E δ ( by positivity ) hp.2;
      exact ⟨ s, Finset.mem_Icc.mpr ⟨ neg_le_of_abs_le <| Int.le_floor.mpr <| mod_cast hs₁, le_of_abs_le <| Int.le_floor.mpr <| mod_cast hs₁ ⟩, hs₂ ⟩;
    refine' le_trans ( Nat.cast_le.mpr ( Finset.card_le_card h_cover ) ) _;
    refine' mod_cast le_trans ( Finset.card_biUnion_le ) _;
    refine' le_trans ( Finset.sum_le_sum fun x hx => show #_ ≤ 2 from _ ) _;
    · have := card_prime_factors_dyadic_le_two X ( E - x * q ) ?_ ?_;
      · refine' le_trans _ this;
        exact Finset.card_mono fun p hp => Finset.mem_filter.mpr ⟨ Finset.mem_Icc.mpr ⟨ by linarith [ hF p ( Finset.mem_filter.mp hp |>.1 ) ], by linarith [ hF p ( Finset.mem_filter.mp hp |>.1 ) ] ⟩, hF p ( Finset.mem_filter.mp hp |>.1 ) |>.1, Finset.mem_filter.mp hp |>.2 ⟩;
      · exact fun h => hqE <| by rw [ sub_eq_zero ] at h; exact h.symm ▸ dvd_mul_left _ _;
      · -- Since $|x| \leq m$, we have $|x| \leq 2 * δ * X$.
        have hx_bound : |x| ≤ 2 * δ * X := by
          exact le_trans ( mod_cast abs_le.mpr ⟨ by linarith [ Finset.mem_Icc.mp hx ], by linarith [ Finset.mem_Icc.mp hx ] ⟩ ) ( Int.floor_le _ );
        rw [ mul_div, div_mul_eq_mul_div, le_div_iff₀ ] at * <;> norm_cast at * <;> cases X <;> norm_num at *;
        · aesop;
        · have h_card_bound : (F.card : ℤ) ≤ (2 * (Nat.succ ‹_›) + 1) := by
            exact_mod_cast le_trans ( Finset.card_le_card ( show F ⊆ Finset.Icc ( Nat.succ ‹_› ) ( 2 * ( Nat.succ ‹_› ) ) from fun p hp => Finset.mem_Icc.mpr ⟨ by linarith [ hF p hp ], by linarith [ hF p hp ] ⟩ ) ) ( by simp +arith +decide );
          norm_num [ abs_lt ] at *;
          constructor <;> cases abs_cases x <;> nlinarith [ pow_succ' ( ( ‹_› : ℕ ) : ℤ ) 2 ];
        · exact absurd hq2X hq.ne_zero;
    · norm_num [ mul_comm ];
  -- Since $T$ is a finite set of integers, its cardinality is at most $2m + 1$.
  have hT_card : T.card ≤ 2 * m + 1 := by
    simp +zetaDelta at *;
    exact ⟨ by linarith, by linarith [ show ⌊2 * ( ( F.card : ℝ ) / ( 32 * X ) ) * X⌋ ≥ 0 by positivity ] ⟩;
  -- Since $m \leq 2\delta X$, we have $2m + 1 \leq 4\delta X + 1$.
  have hT_card_le : (T.card : ℝ) ≤ 4 * δ * X + 1 := by
    linarith [ Int.floor_le ( 2 * δ * X ), Int.lt_floor_add_one ( 2 * δ * X ), ( by norm_cast : ( T.card : ℝ ) ≤ 2 * m + 1 ) ];
  by_cases hX : X = 0 <;> simp_all +decide [ mul_comm ];
  nlinarith [ show ( F.card : ℝ ) ≥ 8 by norm_cast, show ( X : ℝ ) ≥ 1 by exact Nat.one_le_cast.mpr ( Nat.pos_of_ne_zero hX ), mul_div_cancel₀ ( F.card : ℝ ) ( by positivity : ( 32 * X : ℝ ) ≠ 0 ) ]

/-
**Dispersion energy bound** (`30 §1`):
    `∑_{p ∈ F} ‖E·q̄/p‖² ≥ |F|³/(2^11 X²) =: G_F`.

    **Status**: `sorry`.  Follows from `dispersion_residue_count`: at least half
    the primes have phase `> δ = |F|/(32X)`, each contributing `> δ²`.
-/

lemma phaseP1 (p q : ℕ) (hp : p.Prime) (hq : q.Prime) (hpq : p ≠ q)
    (a : (p : ℕ) → ZMod p) (w : ZMod q) :
    phase (ZMod.valMinAbs (a p) - ZMod.valMinAbs w) q p
      ≤ |(crtRepr p q (a p) w : ℝ)| / ((p : ℝ) * q) + 1 / (2 * p) := by
  haveI := Fact.mk hp
  haveI := Fact.mk hq;
  -- Let H := crtRepr p q (a p) w, ãp := ZMod.valMinAbs (a p), w̃ := ZMod.valMinAbs w, E := ãp - w̃, and q̄ := ((q : ZMod p)⁻¹).val.
  set H := crtRepr p q (a p) w
  set ap := (a p).valMinAbs
  set wtilde := w.valMinAbs
  set E := ap - wtilde
  set qbar := ((q : ZMod p)⁻¹).val;
  -- From v*q ≡ E (mod p): multiply both sides by (q:ZMod p)⁻¹: v ≡ E * (q:ZMod p)⁻¹ (mod p).
  obtain ⟨k, hk⟩ : ∃ k : ℤ, E * qbar - (H - wtilde) / q = p * k := by
    have h_mod : (H - wtilde) / q * q ≡ E [ZMOD p] := by
      have h_mod : (H : ZMod p) = ap := by
        convert crtRepr_congr_left p q ( a p ) w _ _ _;
        · convert ZMod.coe_valMinAbs ( a p );
        · exact hp.coprime_iff_not_dvd.mpr fun h => hpq <| Nat.prime_dvd_prime_iff_eq hp hq |>.1 h;
        · exact hp.pos;
        · exact hq.pos;
      rw [ Int.ediv_mul_cancel ];
      · simp_all +decide [ ← ZMod.intCast_eq_intCast_iff ];
        grind;
      · have h_mod : (H : ZMod q) = w := by
          convert crtRepr_congr_right p q ( a p ) w _ _ _ using 1;
          · exact hp.coprime_iff_not_dvd.mpr fun h => hpq <| Nat.prime_dvd_prime_iff_eq hp hq |>.1 h;
          · exact hp.pos;
          · exact hq.pos;
        rw [ ← ZMod.intCast_zmod_eq_zero_iff_dvd ] ; aesop;
    have h_mod : (H - wtilde) / q ≡ E * qbar [ZMOD p] := by
      simp_all +decide [ ← ZMod.intCast_eq_intCast_iff ];
      simp +zetaDelta at *;
      rw [ ← h_mod, mul_assoc, mul_inv_cancel₀ ( by rw [ Ne.eq_def, ZMod.natCast_eq_zero_iff ] ; exact fun h => hpq <| by have := Nat.prime_dvd_prime_iff_eq hp hq; tauto ), mul_one ];
    exact h_mod.dvd;
  -- So |x - round x| = |(v:ℝ)/p - round ((v:ℝ)/p)|.
  have h_abs : phase E q p = |(H - wtilde : ℝ) / (p * q) - round ((H - wtilde : ℝ) / (p * q))| := by
    -- Substitute hk into the expression for x - round x.
    have h_subst : (E : ℝ) * qbar / p = (H - wtilde : ℝ) / (p * q) + k := by
      rw [ div_add', div_eq_div_iff ] <;> norm_cast <;> simp_all +decide [ hp.ne_zero, hq.ne_zero ];
      rw [ ← Int.ediv_mul_cancel ( show ( q : ℤ ) ∣ H - wtilde from ?_ ) ] ; linear_combination hk * p * q;
      have h_div : (crtRepr p q (a p) w : ZMod q) = w := by
        convert crtRepr_congr_right p q ( a p ) w _ _ _ using 1;
        · exact hp.coprime_iff_not_dvd.mpr fun h => hpq <| Nat.prime_dvd_prime_iff_eq hp hq |>.1 h;
        · exact hp.pos;
        · exact hq.pos;
      haveI := Fact.mk hq; simp_all +decide [ ← ZMod.intCast_zmod_eq_zero_iff_dvd ] ;
      aesop;
    unfold phase;
    simp +zetaDelta at *;
    rw [ h_subst, round_add_intCast ] ; norm_num;
  -- So |(v:ℝ)/p - round ((v:ℝ)/p)| ≤ |(v:ℝ)/p|.
  have h_abs_le : |(H - wtilde : ℝ) / (p * q) - round ((H - wtilde : ℝ) / (p * q))| ≤ |(H - wtilde : ℝ) / (p * q)| := by
    convert round_le _ 0 using 1;
    · norm_num;
    · infer_instance;
  -- So |(H - w̃)/(p*q)| ≤ |H|/(p*q) + |w̃|/(p*q).
  have h_abs_le' : |(H - wtilde : ℝ) / (p * q)| ≤ |(H : ℝ)| / (p * q) + |(wtilde : ℝ)| / (p * q) := by
    rw [ abs_div, abs_of_nonneg ( by positivity : ( 0 : ℝ ) ≤ p * q ) ];
    rw [ ← add_div ] ; gcongr ; exact abs_sub _ _;
  -- Since |w̃| ≤ q/2, we have |w̃|/(p*q) ≤ 1/(2*p).
  have h_wtilde_le : |(wtilde : ℝ)| / (p * q) ≤ 1 / (2 * p) := by
    have h_wtilde_le : |(wtilde : ℝ)| ≤ q / 2 := by
      have := ZMod.valMinAbs_mem_Ioc w;
      rw [ le_div_iff₀ ] <;> norm_cast;
      grind;
    rw [ div_le_div_iff₀ ] <;> nlinarith [ show ( p : ℝ ) > 0 by exact Nat.cast_pos.mpr hp.pos, show ( q : ℝ ) > 0 by exact Nat.cast_pos.mpr hq.pos ];
  linarith

/-! ## The squared triangle bound

Combining `phase_sub_le` with `phaseP1` applied to `w` and `w'`:
`phase (w̃' − w̃) q p ≤ |H_w|/(pq) + |H_{w'}|/(pq) + 1/p`, and then
`(α+β+γ)² ≤ 3(α²+β²+γ²)` gives the per-prime squared bound. -/

lemma entropy_inequality (eps : ℝ) (hε0 : 0 < eps) (hε1 : eps < 1) :
    ∃ (Ceps X0 : ℝ), 0 < Ceps ∧ 0 < X0 ∧
      ∀ (X : ℕ), X0 ≤ X → ∀ (NP Fc h : ℕ) (R : ℝ),
        Ceps * (X : ℝ) ^ ((2 : ℝ) / 3) * (Real.log X) ^ ((4 : ℝ) / 3) ≤ R →
        1 ≤ NP → NP ≤ 2 * X → 8 ≤ Fc →
        eps * R / (2 * Real.log (2 * X)) ≤ (Fc : ℝ) →
        (Fc : ℝ) ≤ eps * R / (2 * Real.log (2 * X)) + 1 →
        (h : ℝ) ≤ 7 * R * (2 ^ 11 * (X : ℝ) ^ 2) / (Fc : ℝ) ^ 3 →
        (2 * (X : ℝ)) ^ Fc * (Nat.choose NP h : ℝ) * (2 * (X : ℝ)) ^ h
          ≤ (NP : ℝ) * Real.exp (eps * R) := by
  -- Choose X0 := 3 and Ceps := max ((2^21 * 7 / eps^4) ^ ((1:ℝ)/3)) (8/eps).
  use max ((2^21 * 7 / eps^4) ^ ((1:ℝ)/3)) (8/eps), 3;
  refine' ⟨ by positivity, by positivity, fun X hX NP Fc h R hR hNP hNP' hFc hFc' hFc'' hh => _ ⟩;
  -- Now use the provided inequalities to bound the terms.
  have h_bound : (Fc : ℝ) * Real.log (2 * X) + 2 * h * Real.log (2 * X) ≤ eps * R := by
    -- Use the provided inequalities to bound the terms.
    have h_bound : (Fc : ℝ) * Real.log (2 * X) ≤ eps * R / 2 + Real.log (2 * X) := by
      rw [ div_add_one, le_div_iff₀ ] at hFc'' <;> nlinarith [ Real.log_pos ( show ( 2 * X : ℝ ) > 1 by linarith ) ]
    have h_bound' : 2 * h * Real.log (2 * X) ≤ 7 * 2^15 * X^2 * (Real.log (2 * X))^4 / (eps^3 * R^2) := by
      have h_bound' : (h : ℝ) ≤ 7 * R * (2^11 * X^2) / (eps^3 * R^3 / (8 * (Real.log (2 * X))^3)) := by
        have h_bound' : (Fc : ℝ) ^ 3 ≥ (eps * R / (2 * Real.log (2 * X))) ^ 3 := by
          exact pow_le_pow_left₀ ( div_nonneg ( mul_nonneg hε0.le ( show 0 ≤ R by exact le_trans ( by positivity ) hR ) ) ( mul_nonneg zero_le_two ( Real.log_nonneg ( by norm_cast; linarith ) ) ) ) hFc' 3;
        refine le_trans hh ?_;
        gcongr;
        · exact mul_nonneg ( mul_nonneg ( by norm_num ) ( le_trans ( by positivity ) hR ) ) ( by positivity );
